#define HEADER_H 30
#define HINT_H   24
#define MARGIN   10
/* Row height tracks the content font size (Geneva S/M/L), so list / menu / settings
 * rows reflow when the user changes Text Size. Set by ui_set_text_size(); the
 * default matches the medium size below. ROW_H reads it everywhere it lays out rows. */
static int g_rowH = 15;
#define ROW_H    (g_rowH)
#define NARROW_W 420

/* Icon Grid layout styles (Settings > Grid Style). FINDER = the Finder "by Icon"
 * view (icon, 2-line wrapped name, the name highlighted when selected); TILES = each
 * app as an At Ease-style rounded button (icon + name in a framed tile, the whole
 * tile highlighted). */
enum { GRID_FINDER = 0, GRID_TILES, GRID_N };
static const char *kGridStyle[GRID_N] = { "Finder", "Tiles" };
#define ICON_SZ  16            /* list-row icon box (px); 32x32 art fits into it */
#define ICON_GUT 22            /* icon column width incl. the gap before the name */
#define CATLIST_W 140          /* width of the optional categories list panel (left) */

/* Esc-menu row kinds and their labels (indexed by kind). The visible set per run
 * is built into Ui::menuRows by ui_init (Finder rows omitted on the boot shell). */
enum { MROW_SETTINGS, MROW_SHOW_FINDER, MROW_EXIT, MROW_RESTART, MROW_SHUTDOWN, MROW_CHOOSE_OS, MROW_STATUS, MROW_CDLIST };
static const char *kMenuLabel[] = { "Settings", "Show Finder", "Exit to Finder", "Restart", "Shut Down", "System Folder Chooser", "MacAtrium Status", "CD Library" };

/* ---- small helpers -------------------------------------------------------- */

static void l2s(long v, char *buf)               /* long -> C string */
{
    char tmp[16];
    int  n = 0, i = 0;
    int  neg = (v < 0);
    unsigned long u = neg ? (unsigned long)(-v) : (unsigned long)v;
    if (u == 0) tmp[n++] = '0';
    while (u) { tmp[n++] = (char)('0' + (u % 10)); u /= 10; }
    if (neg) tmp[n++] = '-';
    while (n) buf[i++] = tmp[--n];
    buf[i] = '\0';
}

/* Append the multi-disk " [N]" source-disk token to a category label in `buf`
 * (docs/37; N = the volume-table index). No-op with 0/1 library disks, or when
 * `buf` lacks room. Called before the caller's width-truncation. */
static void ui_append_disk_tag(Ui *u, int vol, char *buf, int cap)
{
    char num[16];
    int  len, nn;
    if (!u->vols || u->vols->n <= 1) return;
    if (vol < 0) vol = 0;
    l2s((long)vol, num);
    nn  = (int)strlen(num);
    len = (int)strlen(buf);
    if (len + nn + 4 > cap) return;            /* " [" + num + "]" + NUL */
    buf[len++] = ' ';
    buf[len++] = '[';
    memcpy(buf + len, num, (size_t)nn); len += nn;
    buf[len++] = ']';
    buf[len]   = '\0';
}

static int win_w(Ui *u) { return u->win->portRect.right - u->win->portRect.left; }
static int win_h(Ui *u) { return u->win->portRect.bottom - u->win->portRect.top; }

/* "1991 - Psygnosis - Puzzle, Strategy" from the item's display fields. ASCII
 * separators only — the launcher renders MacRoman, so we avoid non-ASCII glyphs.
 * `out` must hold >= ITEM_VENDOR_LEN + ITEM_GENRE_LEN + 32 bytes. */
static void build_meta(const CatItem *it, char *out)
{
    char num[16];
    out[0] = '\0';
    if (it->year > 0) { l2s(it->year, num); strcat(out, num); }
    if (it->vendor[0]) { if (out[0]) strcat(out, " - "); strcat(out, it->vendor); }
    if (it->genre[0])  { if (out[0]) strcat(out, " - "); strcat(out, it->genre); }
}

/* Word-wrap `s` into `maxw` px, drawing each line from baseline `y` stepping by
 * `dy`, up to `maxlines`. Returns the baseline after the last line drawn. */
static short draw_wrapped(Render *r, short x, short y, short maxw, short dy,
                          const char *s, int ink, int maxlines)
{
    char line[200], cand[200], word[80];
    int  ll = 0, lines = 0, i = 0;
    while (s[i] && lines < maxlines) {
        int wl = 0, cl = 0;
        while (s[i] == ' ') i++;                       /* skip run of spaces */
        while (s[i] && s[i] != ' ' && wl < (int)sizeof word - 1) word[wl++] = s[i++];
        word[wl] = '\0';
        if (wl == 0) break;
        if (ll > 0) { memcpy(cand, line, ll); cl = ll; cand[cl++] = ' '; }
        memcpy(cand + cl, word, wl); cl += wl; cand[cl] = '\0';
        if (ll > 0 && render_text_width(r, cand) > maxw) {
            line[ll] = '\0';
            render_text(r, x, y, line, ink);
            y = (short)(y + dy); lines++;
            memcpy(line, word, wl); ll = wl; line[ll] = '\0';
        } else {
            memcpy(line, cand, cl); ll = cl; line[ll] = '\0';
        }
    }
    if (ll > 0 && lines < maxlines) {
        line[ll] = '\0';
        render_text(r, x, y, line, ink);
        y = (short)(y + dy);
    }
    return y;
}

/* keep the selected row within the visible window */
static int clamp_scroll(Ui *u, int visRows)
{
    ModelCat *c = model_cur_cat(u->m);
    if (!c || c->count == 0) { u->m->topRow = 0; return 0; }
    if (visRows < 1) visRows = 1;
    if (u->m->curItem < u->m->topRow)
        u->m->topRow = u->m->curItem;
    else if (u->m->curItem >= u->m->topRow + visRows)
        u->m->topRow = u->m->curItem - visRows + 1;
    if (u->m->topRow < 0) u->m->topRow = 0;
    return u->m->topRow;
}

/* Content text-size presets (points): Geneva at the Finder filename size (9) up to
 * the old system size (12). The row height — and thus list / menu / settings density
 * and how much of a long name fits — scales with the choice. */
enum { TEXT_SMALL = 9, TEXT_MEDIUM = 10, TEXT_LARGE = 12 };

void ui_set_text_size(Ui *u, int pts)
{
    if (pts < TEXT_SMALL) pts = TEXT_SMALL;
    if (pts > TEXT_LARGE) pts = TEXT_LARGE;
    render_set_text_size(u->r, pts);
    g_rowH = pts + 5;                  /* row spacing tracks the font (S 14 / M 15 / L 17) */
    u->bgValid = 0;                    /* the whole layout reflows around the new size */
}

/* ---- public --------------------------------------------------------------- */

void ui_init(Ui *u, Env *env, Render *r, Model *m, WindowPtr win, int safe)
{
    u->env = env; u->r = r; u->m = m; u->win = win;
    ui_set_text_size(u, TEXT_MEDIUM);   /* Geneva content font, Finder-ish size (main overrides from prefs) */
    u->mode = UI_MODE_LIST;
    u->menuSel = 0;
    u->safe = safe;
    u->status[0] = '\0';
    u->previewPic = 0;
    u->listArt = 0;
    u->artFor = 0;
    u->settingsFocus = 0;
    u->setSel = 0;
    u->ndepths = display_depths(u->depths, UI_MAX_DEPTHS);   /* all OS-supported depths */
    u->vol = sound_available() ? sound_get_vol() : -1;
    u->artPref = 1;                            /* Screenshot is the primary cover (box art on P) */
    u->view = VIEW_CAROUSEL;                   /* default browse view (first-run chooser may change) */
    u->gridStyle = GRID_FINDER;                /* Icon Grid default: Finder layout      */
    u->listFocus = 1;                          /* List view starts focused on the items pane */
    u->sortMode = SORT_NONE; u->sortDesc = 0;  /* List view: curated order until a header click */
    u->listColType = 120;                      /* Name|Type divider, px from the right */
    u->filter[0] = '\0';
    u->setupSel = 0;
    u->carousel = 7;                           /* icons shown: 7 by default (odd 3..25), fit-capped */
    u->sndStartup = 0;                                       /* sounds off by default */
    u->sndShutdown = 0;
    u->ncdevs = 0; u->cdevSel = 0; u->cdevTop = 0;           /* control-panel list */
    u->bgValid = 0;                                          /* force a full first paint */
    u->lastMode = -1;
    u->overlayDrawn = 0; u->lastSel = -1;                    /* overlay partial-redraw state */
    SetRect(&u->panelRect, 0, 0, 0, 0);                      /* no overlay panel shown yet */
    u->setupDrawn = 0; u->lastSetupSel = -1;                 /* chooser partial-redraw state */
    u->catList = 0;                                          /* categories list hidden */
    {
        int i;
        for (i = 0; i < MAX_ITEMS; i++) u->rowIcon[i] = 0;   /* lazy row-icon cache */
    }
    /* Build the Esc menu for this environment. "Show Finder" / "Exit to Finder"
     * only make sense when a separate Finder process exists to front or hand back
     * to — true on System 7 (we're a Startup Item) or System 6 + MultiFinder. On
     * the System-6 boot-shell build the launcher replaced the Finder, so those
     * rows are dropped (canLaunchReturn is false: no Process Manager / Finder). */
    {
        int k = 0;
        u->menuRows[k++] = MROW_SETTINGS;
        u->menuRows[k++] = MROW_STATUS;
        u->menuRows[k++] = MROW_CDLIST;
        if (env->canLaunchReturn) {
            u->menuRows[k++] = MROW_SHOW_FINDER;
            u->menuRows[k++] = MROW_EXIT;
        }
        u->menuRows[k++] = MROW_CHOOSE_OS;
        u->menuRows[k++] = MROW_RESTART;
        u->menuRows[k++] = MROW_SHUTDOWN;
        u->nmenu = k;
    }
}

/* The art base path for an item's main cover. Screenshot (`shot`) is the primary
 * cover by default (artPref==1); the Artwork setting can flip the main pane to
 * box art (`image`). Each falls back to the other so a pane is never needlessly
 * empty. Box art is always reachable full-screen via the P key regardless. */
static const char *art_base(Ui *u, const CatItem *it)
{
    if (u->artPref == 1) return it->shot[0] ? it->shot : it->image;
    return it->image[0] ? it->image : it->shot;
}

void ui_set_status(Ui *u, const char *msg)
{
    strncpy(u->status, msg, sizeof u->status - 1);
    u->status[sizeof u->status - 1] = '\0';
}

const char *ui_current_app(Ui *u)
{
    const CatItem *it = model_cur_item(u->m);
    return it ? it->app : 0;
}

/* The whole current item (for the CD-insert flow, which needs the cd* fields). */
const CatItem *ui_current_item(Ui *u)
{
    return model_cur_item(u->m);
}

const char *ui_current_name(Ui *u)
{
    const CatItem *it = model_cur_item(u->m);
    return it ? it->name : 0;
}

/* Per-game max colour depth (bpp) from the catalog; 0 = no cap. */
int ui_current_maxdepth(Ui *u)
{
    const CatItem *it = model_cur_item(u->m);
    return it ? it->maxDepth : 0;
}

const CtlPanel *ui_current_cdev(Ui *u)
{
    if (u->cdevSel < 0 || u->cdevSel >= u->ncdevs) return 0;
    return &u->cdevs[u->cdevSel];
}

/* ---- drawing -------------------------------------------------------------- */

static Art *load_item_art(Ui *u, const char *image);   /* defined below */

/* Load the current selection's detail art if it isn't already loaded for that
 * item (so a repeat call for the same item is a no-op — never a reload). Returns
 * 1 if it (re)loaded, 0 if already current. Drives both the deferred path
 * (ui_idle -> *_draw_art, so an in-page grid/list move writes the text at once and
 * the cover box blits in on the next tick — never blocking on a PICT decode) and
 * the synchronous path (a full ui_draw, and carousel moves, pre-load so the cover
 * lands in the same repaint instead of flashing in on a second pass). */
static int ensure_art_loaded(Ui *u)
{
    const CatItem *cur = model_cur_item(u->m);
    if (cur == u->artFor) return 0;            /* already loaded for this item */
    if (u->listArt) { art_dispose(u->listArt); u->listArt = 0; }
    if (cur) {
        const char *base = art_base(u, cur);
        if (base && base[0]) u->listArt = load_item_art(u, base);
    }
    u->artFor = cur;
    return 1;
}

/* The small list-row icon for catalog item `catIdx`, lazily loaded and cached
 * (depth-matched like art: 1-bit ICN# .raw, or the icl8 .8.pict on colour
 * screens). NULL if the item has no icon or it won't load. */
static Art *row_icon(Ui *u, int catIdx, const CatItem *it)
{
    if (catIdx < 0 || catIdx >= MAX_ITEMS) return 0;
    if (!u->rowIcon[catIdx] && it->icon[0])
        u->rowIcon[catIdx] = load_item_art(u, it->icon);
    return u->rowIcon[catIdx];
}

/* Drop every cached row icon (e.g. after a depth change — the icl8 colour
 * variant differs from the 1-bit one). */
static void dispose_row_icons(Ui *u)
{
    int i;
    for (i = 0; i < MAX_ITEMS; i++)
        if (u->rowIcon[i]) { art_dispose(u->rowIcon[i]); u->rowIcon[i] = 0; }
}

/* Invalidate the per-item art caches after a category page loads. The paged
 * catalog reuses one items array for every category (main.c), so both caches
 * alias the *previous* page's items by reused storage: `artFor` is a CatItem*
 * (now pointing at a different title at the same address) and `rowIcon[]` is
 * keyed by the reused slot index. Without this, a new selection that lands on a
 * slot the old page also used keeps the previous item's cover / tile icon.
 * Called by main's PageLoader right after model_set_page. */
void ui_page_changed(Ui *u)
{
    if (u->listArt) { art_dispose(u->listArt); u->listArt = 0; }
    u->artFor = 0;
    dispose_row_icons(u);
}

#define ART_PANE_W 176          /* right-hand art pane width when wide enough */
#define ART_MIN_W  560          /* show the art pane only at this width or more */

/* Art-pane width: the classic 176 px up to 720 px wide (640x480 unchanged), then
 * a proportional ~27% (capped at 360) on bigger screens so the art isn't a sliver
 * at 800x600 / 1024x768. The list takes the rest of the width. */
static int art_pane_w(int W)
{
    int w;
    if (W <= 720) return ART_PANE_W;
    w = W * 27 / 100;
    if (w < ART_PANE_W) w = ART_PANE_W;
    if (w > 360) w = 360;
    return w;
}

/* Mouse affordances on the browse screen (docs/07). The Launch button and the
 * ◀▶ pager are real Control-Manager controls (drawn by ui_paint_controls); the
 * filmstrip tiles are fixed-size columns. Sizes are fixed so hit-testing in
 * ui_click() needs no font metrics (which aren't reliable outside a draw pass). */
#define LAUNCH_W 84
#define LAUNCH_H 22
#define CAR_PAGER_H 16          /* carousel horizontal scroll bar height (== SBW)  */
#define CATBAND_HALF 80         /* clickable half-width of the centred "^ cat v" */

/* The category stepper — the classic Macintosh "little arrows" increment control:
 * a framed box split in two, an up triangle (previous category) over a down triangle
 * (next). Fixed rect at the header band's right edge so ui_click can hit-test it
 * without font metrics (unreliable outside a draw pass). The Settings affordance at
 * the header's LEFT is now a real push button drawn by ui_paint_controls. */
static void cat_stepper_rect(Ui *u, Rect *rr)
{
    int W = win_w(u);
    SetRect(rr, (short)(W / 2 + CATBAND_HALF - 16), 5, (short)(W / 2 + CATBAND_HALF), 25);
}
static void draw_cat_stepper(Ui *u)
{
    Render *r = u->r;
    Rect    box, up, dn;
    short   midY;
    if (!model_cur_cat(u->m)) return;
    cat_stepper_rect(u, &box);
    render_frame(r, &box);
    midY = (short)((box.top + box.bottom) / 2);
    render_hline(r, box.left, box.right, midY);          /* two stacked arrow buttons */
    SetRect(&up, box.left, box.top, box.right, midY);
    SetRect(&dn, box.left, midY, box.right, box.bottom);
    render_arrow(r, &up, 2);                             /* up   = previous category */
    render_arrow(r, &dn, 3);                             /* down = next category     */
}

static void draw_safe(Ui *u)
{
    Render *r = u->r;
    Rect full = u->win->portRect;
    int W = win_w(u), H = win_h(u);
    short cy = (short)(H / 2 - 30);

    render_fill(r, &full, FILL_BG);

    render_base_text(r);
    {
        const char *t = "MacAtrium";
        short x = (short)((W - render_text_width(r, t)) / 2);
        render_text(r, x, (short)(cy - 24), t, INK_TITLE);
    }
    {
        const char *t = "No catalog found.";
        short x = (short)((W - render_text_width(r, t)) / 2);
        render_text(r, x, cy, t, INK_NORMAL);
    }
    {
        const char *t = "Expected: /MacAtrium/metadata/catalog.jsonl";
        short x = (short)((W - render_text_width(r, t)) / 2);
        render_text(r, x, (short)(cy + 22), t, INK_DIM);
    }
    {
        const char *t = "Press Esc for Restart / Shut Down.";
        short x = (short)((W - render_text_width(r, t)) / 2);
        render_text(r, x, (short)(cy + 50), t, INK_NORMAL);
    }
}

/* A small "CD" chip in the top-left corner of `box`, marking a CD-based title whose
 * disc auto-inserts on launch (docs/45). Themed primitives → reads at any depth. */
static void draw_cd_badge(Render *r, const Rect *box)
{
    Rect b;
    SetRect(&b, (short)(box->left + 2), (short)(box->top + 2),
                (short)(box->left + 22), (short)(box->top + 15));
    render_fill(r, &b, FILL_SEL);
    render_frame(r, &b);
    render_text(r, (short)(b.left + 4), (short)(b.bottom - 3), "CD", INK_SELECTED);
}

/* Draw one carousel tile: the item's app icon (depth-matched, cached) centered
 * at (cx, cy) in an sz x sz box, or a framed placeholder if it has no icon. */
static void draw_tile(Ui *u, int catIdx, const CatItem *it, short cx, short cy, short sz)
{
    Rect box;
    Art *ic;
    short h = (short)(sz / 2);
    SetRect(&box, (short)(cx - h), (short)(cy - h), (short)(cx + h), (short)(cy + h));
    ic = it->icon[0] ? row_icon(u, catIdx, it) : 0;
    if (ic) art_draw_fit(ic, &box);
    else    render_frame(u->r, &box);          /* icon-less item placeholder */
    if (it->cdImage[0]) draw_cd_badge(u->r, &box);
}

/* The browse screen: a horizontal icon carousel (Left/Right scroll the games,
 * the selected one enlarged in the centre; Up/Down change category) over a
 * detail panel (the selected game's art + name / developer / genre / blurb).
 * Reuses the lazily-cached app icons (carousel) and the depth-matched art
 * loader (detail pane), so a move is mostly cheap icon blits. */
/* Browse-screen geometry, computed once and shared by draw_carousel() (drawing)
 * and ui_click() (hit-testing) so the drawn pixels and the clickable rects can
 * never drift apart. Holds the band rects, the centre/side tile metrics, and the
 * mouse-control rects (gear, category band, the ◀▶ arrows, the Launch button). */
typedef struct {
    int   W, H;
    short clx;                       /* content left edge (cat list or 0)        */
    short carTop, carBot, detTop, detBot;
    int   hasItems, count;
    int   nTiles;                    /* equal-size tiles shown in the strip       */
    int   page, first, selOnPage;    /* page = curItem/nTiles; first = page*nTiles */
    short stripX0, iconCy, tileW, tileSz, nameBase;
    Rect  catBand, launchBtn, pager;   /* pager = horizontal scroll bar (band bottom) */
    short catMidX;                   /* split: click < = prev cat, >= = next cat */
} CarLayout;

static void carousel_layout(Ui *u, CarLayout *L)
{
    int       W = win_w(u), H = win_h(u);
    ModelCat *cat = model_cur_cat(u->m);
    int       usable = H - HEADER_H - HINT_H;
    int       carH   = usable * 42 / 100;
    if (carH < 120) carH = 120;

    L->W = W; L->H = H;
    L->clx    = (short)(u->catList ? CATLIST_W : 0);
    L->carTop = HEADER_H;
    L->carBot = (short)(HEADER_H + carH);
    L->detTop = (short)(L->carBot + 1);
    L->detBot = (short)(H - HINT_H);
    L->count  = cat ? cat->count : 0;
    L->hasItems = (cat && cat->count > 0);

    L->catMidX = (short)(W / 2);
    SetRect(&L->catBand, (short)(W / 2 - CATBAND_HALF), 2,
            (short)(W / 2 + CATBAND_HALF), (short)(HEADER_H - 2));

    SetRect(&L->launchBtn, 0, 0, 0, 0);
    SetRect(&L->pager,     0, 0, 0, 0);
    L->nTiles = L->page = L->first = L->selOnPage = 0;
    L->stripX0 = L->iconCy = L->tileW = L->tileSz = L->nameBase = 0;

    if (L->hasItems) {
        /* Budget the chrome below the strip from the band bottom up: the ◀▶ pager
         * (horizontal scroll bar) along the bottom edge, the centred item name above
         * it, then the Launch button; the equal-size tiles fill what's left. The pager
         * + Launch are real controls (ui_paint_controls); only the name is drawn. A
         * fixed strip (no re-centring hero) lets an in-page move repaint just the two
         * affected tiles; crossing the page edge scrolls a full screenful. */
        short cx        = (short)((L->clx + W) / 2);
        short pagerTop  = (short)(L->carBot - CAR_PAGER_H);
        short nameBase  = (short)(pagerTop - 5);
        short launchBot = (short)(nameBase - ROW_H);
        short launchTop = (short)(launchBot - LAUNCH_H);
        short tileBot   = (short)(launchTop - 6);
        short tileTop   = (short)(L->carTop + 4);
        short tileSz    = (short)(tileBot - tileTop - 8);
        short tileW;
        int   stripL    = L->clx + MARGIN, stripR = W - MARGIN;
        int   stripW    = stripR - stripL, nTiles, userMax;
        if (tileSz > 64) tileSz = 64;
        if (tileSz < 36) tileSz = 36;
        tileW  = (short)(tileSz + 18);             /* equal column = icon + gap */
        nTiles = stripW / tileW;
        /* `carousel` is the user's odd 3..25 count -> here the strip's tile count,
         * capped by what fits (auto-grows on a wider screen). */
        userMax = u->carousel;
        if (userMax < 3)  userMax = 3;
        if (userMax > 25) userMax = 25;
        if (nTiles > userMax) nTiles = userMax;
        if (nTiles < 1) nTiles = 1;

        L->nTiles    = nTiles;
        L->page      = u->m->curItem / nTiles;
        L->first     = L->page * nTiles;
        L->selOnPage = u->m->curItem - L->first;
        L->tileSz    = tileSz;
        L->tileW     = tileW;
        L->stripX0   = (short)(stripL + (stripW - nTiles * tileW) / 2);
        L->iconCy    = (short)((tileTop + tileBot) / 2);
        L->nameBase  = nameBase;

        SetRect(&L->launchBtn, (short)(cx - LAUNCH_W / 2), launchTop,
                (short)(cx + LAUNCH_W / 2), launchBot);
        SetRect(&L->pager, (short)(L->clx + MARGIN), pagerTop,
                (short)(W - MARGIN), L->carBot);
    }
}

/* The icon box (and optionally the full erase/highlight column) for visible strip
 * slot s (0..nTiles-1). Shared by draw + click + the incremental redraw so the drawn
 * pixels and the clickable/dirty rects can never drift apart. */
static int carousel_tile_box(const CarLayout *L, int slot, Rect *icon, Rect *col)
{
    short x0, cx, h;
    if (slot < 0 || slot >= L->nTiles) return 0;
    x0 = (short)(L->stripX0 + slot * L->tileW);
    cx = (short)(x0 + L->tileW / 2);
    h  = (short)(L->tileSz / 2);
    if (icon) SetRect(icon, (short)(cx - h), (short)(L->iconCy - h),
                      (short)(cx + h), (short)(L->iconCy + h));
    if (col)  SetRect(col, x0, L->carTop,
                      (short)(x0 + L->tileW), (short)(L->iconCy + h + 8));
    return 1;
}

/* The centred selected-item name strip, just above the pager — its own rect so the
 * incremental redraw can erase + redraw only the name when the selection changes. */
static void carousel_name_band(const CarLayout *L, Rect *nb)
{
    SetRect(nb, (short)(L->clx + MARGIN), (short)(L->nameBase - ROW_H + 1),
            (short)(L->W - MARGIN), (short)(L->nameBase + 3));
}

/* The framed detail-cover rect, from the shared layout — so draw_carousel and the
 * targeted ui_draw_art agree on where the cover goes. */
static void detail_art_rect(const CarLayout *L, Rect *ar)
{
    short artW = (short)((L->W - L->clx) * 2 / 5);
    if (artW > 220) artW = 220;
    SetRect(ar, (short)(L->clx + MARGIN), (short)(L->detTop + MARGIN),
            (short)(L->clx + MARGIN + artW), (short)(L->detBot - MARGIN));
}

/* Paint the detail cover into its box: clear (so a targeted refresh erases the
 * previous item's art), frame, then the loaded cover — or "(no art)" once a load
 * for this item found nothing; empty until the cover has loaded. The ONE place all
 * three views' covers settle: on the off-screen path load the art synchronously here
 * so the cover lands in the same pass as the text (no text->image->text double draw);
 * the direct-draw path leaves it deferred (ui_idle loads, then draw_art repaints this
 * box) so a fast scroll never blocks on a PICT decode. */
static void draw_detail_art(Ui *u, const Rect *ar)
{
    Render        *r;
    const CatItem *cur;
    int            loaded;
    /* Pure draw — no load here. Full repaints pre-load the cover (ui_draw /
     * carousel_draw_sel) so it lands in the same pass; an in-page grid/list move
     * leaves it unloaded and lets the deferred idle (ui_idle -> *_draw_art) blit
     * just the cover box in once it decodes — so the move never blocks on a PICT
     * decode or re-renders the name/blurb. */
    r      = u->r;
    cur    = model_cur_item(u->m);
    loaded = (cur && cur == u->artFor);
    render_fill(r, ar, FILL_BG);
    render_frame(r, ar);
    if (loaded && u->listArt) {
        Rect inner = *ar;
        InsetRect(&inner, 4, 4);
        art_draw_fit(u->listArt, &inner);
    } else if (loaded) {
        const char *t = "(no art)";
        render_text(r, (short)(ar->left + ((ar->right - ar->left) - render_text_width(r, t)) / 2),
                    (short)((ar->top + ar->bottom) / 2), t, INK_DIM);
    }
}

/* ---- key-cap hints ----------------------------------------------------------
 * The browse footer shows the controls as little key-caps — a rounded frame with
 * the key's glyph, then the action it performs — instead of a console-style text
 * strip. Evokes the Key Caps desk accessory + the HIG way of showing keys. Chicago
 * has no arrow/return/escape glyphs (only Apple/command at 0x11-0x14), so those are
 * drawn (render_arrow/render_return); letter keys use the font. */
#define KEYCAP_H    14            /* key-cap height                            */
#define KEYCAP_ARW  14            /* width of an arrow / single-symbol cap     */
#define KEYCAP_RET  18            /* width of the return cap                   */
#define KEYCAP_GAP  16            /* space between hint groups                 */

/* A hint group: one or two key-caps then an action label. A key spec is "<" ">"
 * "^" "v" (arrows), "ret" (return hook), or a short literal ("esc"/"I"/"P"). */
typedef struct { const char *k1, *k2, *label; } HintGroup;

static short keycap_w(Ui *u, const char *spec)
{
    if (!strcmp(spec, "<") || !strcmp(spec, ">") ||
        !strcmp(spec, "^") || !strcmp(spec, "v")) return KEYCAP_ARW;
    if (!strcmp(spec, "ret"))                     return KEYCAP_RET;
    return (short)(render_text_width(u->r, spec) + 9);
}

/* Draw one key-cap at (x, top); returns its width. */
static short draw_keycap(Ui *u, short x, short top, const char *spec)
{
    Render *r = u->r;
    short   w = keycap_w(u, spec);
    Rect    cap;
    int     dir = !strcmp(spec, "<") ? 0 : !strcmp(spec, ">") ? 1 :
                  !strcmp(spec, "^") ? 2 : !strcmp(spec, "v") ? 3 : -1;
    SetRect(&cap, x, top, (short)(x + w), (short)(top + KEYCAP_H));
    render_round_frame(r, &cap);
    if (dir >= 0)                 render_arrow(r, &cap, dir);
    else if (!strcmp(spec, "ret")) render_return(r, &cap);
    else {
        short tw = render_text_width(r, spec);
        render_text(r, (short)(x + (w - tw) / 2), (short)(top + KEYCAP_H - 4), spec, INK_NORMAL);
    }
    return w;
}

/* Lay out a centred row of hint groups within [xL, xR], the caps' tops at `top`.
 * Shared by the browse footer and the overlay panels (Esc menu / Settings / Control
 * Panels) so every on-screen key hint reads as the same Macintosh key-caps. */
static void draw_keyhints_box(Ui *u, const HintGroup *g, int n, short xL, short xR, short top)
{
    Render *r = u->r;
    int     i;
    short   total = 0, x;
    for (i = 0; i < n; i++) {
        total = (short)(total + keycap_w(u, g[i].k1));
        if (g[i].k2)    total = (short)(total + 2 + keycap_w(u, g[i].k2));
        if (g[i].label) total = (short)(total + 5 + render_text_width(r, g[i].label));
        if (i < n - 1)  total = (short)(total + KEYCAP_GAP);
    }
    x = (short)(xL + ((xR - xL) - total) / 2);
    if (x < xL) x = xL;
    for (i = 0; i < n; i++) {
        x = (short)(x + draw_keycap(u, x, top, g[i].k1));
        if (g[i].k2) { x = (short)(x + 2); x = (short)(x + draw_keycap(u, x, top, g[i].k2)); }
        if (g[i].label) {
            x = (short)(x + 5);
            render_text(r, x, (short)(top + KEYCAP_H - 3), g[i].label, INK_DIM);
            x = (short)(x + render_text_width(r, g[i].label));
        }
        x = (short)(x + KEYCAP_GAP);
    }
}

/* The browse footer: hint groups centred across the full window width. */
static void draw_keyhints(Ui *u, const HintGroup *g, int n)
{
    int   W = win_w(u), H = win_h(u);
    draw_keyhints_box(u, g, n, MARGIN, (short)(W - MARGIN), (short)(H - HINT_H + 5));
}

/* Shared browse footer (carousel / grid / list): the rule + either the active name
 * filter ("Filter: …  esc clears") or the view's key-cap hints. So every view shows
 * the same controls + the type-to-find affordance, like the carousel always has. */
static void draw_browse_footer(Ui *u, const HintGroup *g, int n)
{
    Render *r = u->r;
    int     W = win_w(u), H = win_h(u);
    render_hline(r, 0, (short)W, (short)(H - HINT_H));
    if (u->filter[0]) {
        char  fb[48];
        short tw;
        strcpy(fb, "Filter: ");
        strncat(fb, u->filter, 24);
        strcat(fb, "    esc clears");
        render_base_text(r);
        tw = render_text_width(r, fb);
        render_text(r, (short)((W - tw) / 2), (short)(H - HINT_H + 15), fb, INK_DIM);
    } else {
        draw_keyhints(u, g, n);
    }
}

/* Draw one fixed strip slot: erase its column (handles deselect + the empty trailing
 * slots on the last page), the item's app icon, and a 2px selection box when selected. */
static void draw_carousel_tile(Ui *u, const CarLayout *L, int slot)
{
    Model    *m   = u->m;
    ModelCat *cat = model_cur_cat(m);
    int       idx = L->first + slot;
    Rect      icon, col;
    if (!cat || !carousel_tile_box(L, slot, &icon, &col)) return;
    render_fill(u->r, &col, FILL_BG);                 /* erase: deselect / empty slot */
    if (idx < 0 || idx >= cat->count) return;
    draw_tile(u, cat->idx[idx], &m->cat->items[cat->idx[idx]],
              (short)((icon.left + icon.right) / 2), L->iconCy, L->tileSz);
    if (idx == m->curItem) {                          /* 2px selection box */
        Rect f = icon;
        InsetRect(&f, -6, -6); render_frame(u->r, &f);
        InsetRect(&f,  1,  1); render_frame(u->r, &f);
    }
}

/* The detail band below the strip: the framed cover (left) + name / year-developer /
 * genre / blurb / tags (right). Shared by the full draw and the incremental redraw,
 * which blits this same band rect; the leading fill lets a shorter blurb / changed
 * meta replace the previous item's text cleanly. */
static void draw_carousel_detail(Ui *u, const CarLayout *L)
{
    Render        *r   = u->r;
    const CatItem *cur = model_cur_item(u->m);
    int            W = L->W;
    short          detTop = L->detTop, detBot = L->detBot;
    char           num[16];
    Rect           ar, band;

    SetRect(&band, L->clx, detTop, (short)W, detBot);
    render_fill(r, &band, FILL_BG);
    render_base_text(r);
    detail_art_rect(L, &ar);
    draw_detail_art(u, &ar);
    if (!cur) return;
    {
        short tx   = (short)(ar.right + 2 * MARGIN);
        short ty   = (short)(detTop + 18);
        short maxw = (short)(W - tx - MARGIN);
        char  buf[ITEM_VENDOR_LEN + 24];

        /* title */
        render_text(r, tx, ty, cur->name, INK_TITLE);
        ty = (short)(ty + ROW_H + 3);

        /* year - developer */
        buf[0] = '\0';
        if (cur->year > 0) { l2s(cur->year, num); strcat(buf, num); }
        if (cur->vendor[0]) {
            if (buf[0]) strcat(buf, " - ");
            strncat(buf, cur->vendor, sizeof buf - strlen(buf) - 1);
        }
        if (buf[0]) { render_text(r, tx, ty, buf, INK_DIM); ty = (short)(ty + ROW_H); }

        /* genre on its own line */
        if (cur->genre[0]) {
            char g[ITEM_GENRE_LEN + 8];
            strcpy(g, "Genre: ");
            strncat(g, cur->genre, ITEM_GENRE_LEN);
            render_text(r, tx, ty, g, INK_DIM);
            ty = (short)(ty + ROW_H);
        }
        ty = (short)(ty + 6);

        /* description — or, when this Mac can't properly run the title, the compat
         * flag (docs/40) drawn in the title ink so it reads as a warning. A transient
         * status line (a just-now launch message) still wins over both. */
        {
            char warn[COMPAT_REASON_LEN];
            if (u->status[0])
                render_text(r, tx, ty, u->status, INK_NORMAL);
            else if (u->env && compat_reason(cur, u->env, warn))
                draw_wrapped(r, tx, ty, maxw, ROW_H, warn, INK_TITLE, 3);
            else if (cur->desc[0])
                draw_wrapped(r, tx, ty, maxw, ROW_H, cur->desc, INK_NORMAL, 7);
        }

        /* tags: the navigational categories, along the panel's last line */
        if (cur->ncats > 0) {
            char tags[ITEM_CAT_LEN * 5];
            int  ci;
            tags[0] = '\0';
            for (ci = 0; ci < cur->ncats; ci++) {
                if (strlen(tags) + strlen(cur->cats[ci]) + 4 >= sizeof tags) break;
                if (tags[0]) strcat(tags, " - ");
                strcat(tags, cur->cats[ci]);
            }
            if (tags[0]) render_text(r, tx, (short)(detBot - 8), tags, INK_DIM);
        }
    }
}

static void draw_carousel(Ui *u)
{
    Render        *r   = u->r;
    Model         *m   = u->m;
    ModelCat      *cat = model_cur_cat(m);
    const CatItem *cur = model_cur_item(m);
    Rect           full = u->win->portRect;
    char           num[16];
    CarLayout      L;
    int            W, H;
    short          clx, carTop, carBot;

    carousel_layout(u, &L);
    W = L.W; H = L.H; clx = L.clx;
    carTop = L.carTop; carBot = L.carBot;

    render_fill(r, &full, FILL_BG);

    /* ---- optional categories list (left panel) ---- */
    if (u->catList) {
        short sy = HEADER_H, sb = (short)(H - HINT_H);
        int   rows = (sb - sy - 4) / ROW_H;
        int   top, i;
        Rect  sr;
        SetRect(&sr, 0, sy, CATLIST_W, sb);
        render_fill(r, &sr, FILL_PANEL);
        render_frame(r, &sr);
        top = m->curCat - rows / 2;
        if (top + rows > m->ncats) top = m->ncats - rows;
        if (top < 0) top = 0;
        for (i = 0; i < rows; i++) {
            int   ci = top + i;
            short y0 = (short)(sy + 2 + i * ROW_H), base = (short)(y0 + ROW_H - 5);
            int   sel;
            char  nm[ITEM_CAT_LEN];
            if (ci >= m->ncats) break;
            sel = (ci == m->curCat);
            SetRect(&sr, 2, y0, (short)(CATLIST_W - 2), (short)(y0 + ROW_H));
            render_fill(r, &sr, sel ? FILL_SEL : FILL_PANEL);
            strncpy(nm, m->cats[ci].name, sizeof nm - 1); nm[sizeof nm - 1] = '\0';
            while (nm[0] && render_text_width(r, nm) > CATLIST_W - 14) nm[strlen(nm) - 1] = '\0';
            render_text(r, 8, base, nm, sel ? INK_SELECTED : INK_NORMAL);
        }
    }

    /* (a full repaint pre-loads the detail cover in ui_draw on the off-screen path, so
     * it lands in this same pass; draw_detail_art itself is now a pure draw.) */

    /* ---- header: the category (with its little-arrows stepper) + N / M. The
     * Settings button (header left) is a real control drawn in ui_paint_controls. ---- */
    render_base_text(r);
    if (cat) {
        char  cl[ITEM_CAT_LEN + 8];
        short cw, maxw = (short)(2 * (CATBAND_HALF - 28));
        /* the category name in Chicago (the system heading face); the little-arrows
         * stepper sits just past the header band's right edge */
        render_sys_text(r);
        strncpy(cl, cat->name, sizeof cl - 1); cl[sizeof cl - 1] = '\0';
        ui_append_disk_tag(u, cat->vol, cl, (int)sizeof cl);   /* [N] when multi-disk (docs/37) */
        while (cl[0] && render_text_width(r, cl) > maxw) cl[strlen(cl) - 1] = '\0';
        cw = render_text_width(r, cl);
        render_text(r, (short)((W - cw) / 2), 20, cl, INK_NORMAL);
        render_base_text(r);                          /* counter back in the body face */
        draw_cat_stepper(u);
        {
            char line[24];
            l2s(m->curItem + 1, num); strcpy(line, num);
            strcat(line, " / ");
            l2s(cat->count, num); strcat(line, num);
            render_text(r, (short)(W - MARGIN - render_text_width(r, line)), 20, line, INK_DIM);
        }
    }
    render_hline(r, 0, (short)W, (short)(HEADER_H - 1));

    /* ---- carousel band: a fixed strip of equal tiles (no re-centring hero) ----
     * The page = curItem / nTiles; the strip shows [first, first+nTiles), the
     * selected tile boxed at selOnPage. ←/→ move the selection by one (carousel_nav);
     * crossing the page edge scrolls in the next screenful (a full draw). The ◀▶
     * pager + Launch are real controls (ui_paint_controls); only the centred name is
     * drawn here, just above the pager. */
    if (!cat || cat->count == 0) {
        const char *t = "(no items in this category)";
        render_text(r, (short)(clx + (W - clx - render_text_width(r, t)) / 2),
                    (short)((carTop + carBot) / 2), t, INK_DIM);
    } else {
        int s;
        for (s = 0; s < L.nTiles; s++) draw_carousel_tile(u, &L, s);
        if (cur) {
            short nw = render_text_width(r, cur->name);
            render_text(r, (short)(clx + (W - clx - nw) / 2), L.nameBase,
                        cur->name, INK_TITLE);
        }
    }
    render_hline(r, clx, (short)W, carBot);

    /* ---- detail band: cover (left) + name / meta / blurb (right). The cover is
     * loaded synchronously above (off-screen path) or by ui_idle once the selection
     * settles (direct-draw path; that load repaints ONLY the cover box). ---- */
    draw_carousel_detail(u, &L);

    /* remember the page + selection this full draw painted, so an in-page ←/→ move
     * (carousel_draw_sel) can repaint just the two affected tiles + detail */
    u->lastDrawnItem = u->m->curItem;
    u->lastDrawnTop  = L.page;
    u->lastDrawnCat  = u->m->curCat;

    /* ---- footer: control key-caps (or the active filter) ---- */
    if (u->settingsFocus) {
        static const HintGroup g[] = { {"ret", 0, "Settings"}, {"v", 0, "Back"} };
        render_hline(r, 0, (short)W, (short)(H - HINT_H));
        draw_keyhints(u, g, 2);
    } else {
        static const HintGroup g[] = {
            {"<", ">", "Game"}, {"^", "v", "Cat"}, {"ret", 0, "Play"},
            {"A-Z", 0, "Find"}, {"esc", 0, "Menu"}
        };
        draw_browse_footer(u, g, 5);
    }
}

/* Settings is a real Mac window (main.c run_settings_dialog); the row model it
 * renders + drives lives further down (settings_adjust_row + ui_setting_*). The
 * SET_N / SET_ROW_* indices below are shared by both. */
/* Browse-view display names (Settings "Browse View" row + the first-run chooser)
 * and one-line descriptions (chooser only). Defined here so ui_setting_value can
 * name the current view; draw_setup (further down) reuses them. */
static const char *kViewName[VIEW_N] = { "Carousel", "Icon Grid", "List Browser" };
static const char *kViewDesc[VIEW_N] = {
    "Flip through big covers. Best for keyboard / controller.",
    "A grid of icons, like the Finder. Good with a mouse.",
    "Categories + a list with screenshots. Best for big libraries."
};

#define SET_N 17
#define SET_ROW_VIEW      6             /* browse view: Carousel / Icon / List      */
#define SET_ROW_MENUBAR   9             /* System menu bar: Shown / Hidden          */
#define SET_ROW_TITLEBAR  10            /* window title bar: Shown / Hidden         */
#define SET_ROW_TEXTSIZE  11            /* content text size: Small / Medium / Large */
#define SET_ROW_GRIDSTYLE 12            /* Icon Grid layout: Finder / Tiles         */
#define SET_ROW_APPEARANCE 13           /* era control look: Auto / Sys6 / Sys7 / Platinum */
#define SET_ROW_CDINSERT   14           /* CD auto-insert On/Off (docs/45)          */
#define SET_ROW_CDTIMEOUT  15           /* CD mount wait, seconds (docs/45)         */
#define SET_ROW_CTLPANELS (SET_N - 1)   /* the action row (opens the cdev list)     */

/* The Control Panels list (reached from Settings -> Control Panels): a scrollable
 * panel of the System's `cdev` files; Return opens the selected one via the
 * Finder, Esc returns to Settings. */
static void draw_ctlpanels(Ui *u)
{
    Render *r = u->r;
    int     W = win_w(u), H = win_h(u);
    int     pw = 320;
    int     rows = 9;                       /* visible list rows */
    int     ph = rows * (ROW_H + 2) + 56;
    short   px = (short)((W - pw) / 2);
    short   py = (short)((H - ph) / 2);
    Rect    panel, rr;
    int     i;

    SetRect(&panel, px, py, (short)(px + pw), (short)(py + ph));
    u->panelRect = panel;                                    /* blit/erase region */
    render_fill(r, &panel, FILL_PANEL);
    render_frame(r, &panel);

    render_base_text(r);
    render_text(r, (short)(px + MARGIN), (short)(py + 22), "Control Panels", INK_TITLE);
    render_hline(r, px, (short)(px + pw), (short)(py + 30));

    /* keep the selection in view */
    if (u->cdevSel < u->cdevTop) u->cdevTop = u->cdevSel;
    else if (u->cdevSel >= u->cdevTop + rows) u->cdevTop = u->cdevSel - rows + 1;
    if (u->cdevTop < 0) u->cdevTop = 0;

    if (u->ncdevs == 0) {
        render_text(r, (short)(px + MARGIN), (short)(py + 52),
                    "(none found)", INK_DIM);
    } else {
        for (i = 0; i < rows; i++) {
            int   idx = u->cdevTop + i;
            short y0  = (short)(py + 38 + i * (ROW_H + 2));
            short base = (short)(y0 + ROW_H - 5);
            int   sel = (idx == u->cdevSel);
            char  nm[64];
            const unsigned char *p;
            int   k;
            if (idx >= u->ncdevs) break;
            p = u->cdevs[idx].name;
            for (k = 0; k < p[0] && k < 63; k++) nm[k] = (char)p[k + 1];
            nm[k] = '\0';
            SetRect(&rr, (short)(px + 4), y0, (short)(px + pw - 4), (short)(y0 + ROW_H));
            render_fill(r, &rr, sel ? FILL_SEL : FILL_PANEL);
            render_text(r, (short)(px + MARGIN), base, nm, sel ? INK_SELECTED : INK_NORMAL);
        }
    }

    render_hline(r, px, (short)(px + pw), (short)(py + ph - 22));
    {
        static const HintGroup g[] = { {"^", "v", "Select"}, {"ret", 0, "Open"}, {"esc", 0, "Back"} };
        draw_keyhints_box(u, g, 3, (short)(px + 4), (short)(px + pw - 4), (short)(py + ph - 18));
    }
}

static void draw_preview(Ui *u)
{
    Render *r = u->r;
    int     W = win_w(u), H = win_h(u);
    Rect    full = u->win->portRect;
    Rect    art;
    const CatItem *it = model_cur_item(u->m);

    render_fill(r, &full, FILL_BG);

    /* title */
    render_base_text(r);
    if (it)
        render_text(r, MARGIN, 20, it->name, INK_TITLE);
    render_hline(r, 0, (short)W, (short)(HEADER_H - 1));

    /* art area between header and hint bar */
    SetRect(&art, MARGIN, (short)(HEADER_H + MARGIN),
            (short)(W - MARGIN), (short)(H - HINT_H - MARGIN));
    if (u->previewPic)
        art_draw_fit(u->previewPic, &art);
    else
        render_text(r, MARGIN, (short)(H / 2), "(no artwork)", INK_DIM);

    render_hline(r, 0, (short)W, (short)(H - HINT_H));
    {
        const char *hint = "any key  back";
        short x = (short)((W - render_text_width(r, hint)) / 2);
        render_text(r, x, (short)(H - 7), hint, INK_DIM);
    }
}

/* The More Info card (full screen): title, year/developer, genre, the wrapped
 * description, and the box art shown large on the right. */
static void draw_info(Ui *u)
{
    Render *r = u->r;
    int     W = win_w(u), H = win_h(u);
    Rect    full = u->win->portRect;
    const CatItem *it = model_cur_item(u->m);
    short   artW = (short)(W * 2 / 5);            /* right ~40% for the art */
    short   textR = (short)(W - artW - 2 * MARGIN);
    short   x = MARGIN, y;

    render_fill(r, &full, FILL_BG);
    render_base_text(r);

    if (!it) {
        render_text(r, MARGIN, (short)(H / 2), "(no item selected)", INK_DIM);
        render_hline(r, 0, (short)W, (short)(H - HINT_H));
        return;
    }

    render_text(r, x, 24, it->name, INK_TITLE);
    render_hline(r, 0, (short)W, (short)(HEADER_H - 1));

    y = (short)(HEADER_H + 16);
    {
        char num[16], meta[ITEM_VENDOR_LEN + 24];
        meta[0] = '\0';
        if (it->year > 0) { l2s(it->year, num); strcat(meta, num); }
        if (it->vendor[0]) { if (meta[0]) strcat(meta, " - "); strcat(meta, it->vendor); }
        if (meta[0]) { render_text(r, x, y, meta, INK_NORMAL); y = (short)(y + ROW_H); }
    }
    if (it->genre[0]) {
        char g[ITEM_GENRE_LEN + 8];
        strcpy(g, "Genre: ");
        strncat(g, it->genre, ITEM_GENRE_LEN);
        render_text(r, x, y, g, INK_DIM);
        y = (short)(y + ROW_H);
    }
    y = (short)(y + 8);
    /* compatibility flag (docs/40): warn — never block — that this Mac may not run it. */
    {
        char warn[COMPAT_REASON_LEN];
        if (u->env && compat_reason(it, u->env, warn)) {
            y = draw_wrapped(r, x, y, textR, ROW_H, warn, INK_TITLE, 3);
            y = (short)(y + 6);
        }
    }
    if (it->desc[0]) {
        y = draw_wrapped(r, x, y, textR, ROW_H, it->desc, INK_NORMAL, 10);
    }

    if (u->previewPic) {
        Rect ar;
        SetRect(&ar, (short)(W - artW - MARGIN), (short)(HEADER_H + MARGIN),
                (short)(W - MARGIN), (short)(H - HINT_H - MARGIN));
        art_draw_fit(u->previewPic, &ar);
    } else {
        const char *base = art_base(u, it);
        if (!base || !base[0])
            render_text(r, (short)(W - artW), (short)(H / 2), "(no art)", INK_DIM);
    }

    render_hline(r, 0, (short)W, (short)(H - HINT_H));
    {
        const char *hint = "Return  launch        any other key  back";
        short hx = (short)((W - render_text_width(r, hint)) / 2);
        render_text(r, hx, (short)(H - 7), hint, INK_DIM);
    }
}

/* The About card (Apple > About MacAtrium): app name, a one-line description, and
 * the build stamp. A full-screen card like the Info/Preview views — any key/click
 * dismisses it. */
static void draw_about(Ui *u)
{
    Render *r = u->r;
    int     W = win_w(u), H = win_h(u);
    Rect    full = u->win->portRect;
    short   cy = (short)(H / 2 - 44), cw;
    char    ver[40];

    render_fill(r, &full, FILL_BG);
    render_base_text(r);
    { const char *t = "MacAtrium";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), cy, t, INK_TITLE); }
    cy = (short)(cy + 28);
    { const char *t = "A launcher for classic Macintosh games.";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), cy, t, INK_NORMAL); }
    cy = (short)(cy + 20);
    { const char *t = "Pick a title and play. The System runs the rest.";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), cy, t, INK_DIM); }
    cy = (short)(cy + 30);
    strcpy(ver, "build "); strcat(ver, MACATRIUM_VERSION);
    cw = render_text_width(r, ver); render_text(r, (short)((W - cw) / 2), cy, ver, INK_DIM);
    cy = (short)(cy + 22);
    { char os[40]; strcpy(os, "Running on "); env_os_name(u->env->sysVers, os + 11);
      cw = render_text_width(r, os); render_text(r, (short)((W - cw) / 2), cy, os, INK_NORMAL); }

    { const char *t = "Press any key to continue.";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), (short)(H - 14), t, INK_DIM); }
}

/* The clickable rect for setup row i (shared by draw_setup + ui_click). */
static void setup_row_rect(Ui *u, int i, Rect *rr)
{
    int W = win_w(u);
    short bx = (short)(MARGIN + 30), bw = (short)(W - 2 * (MARGIN + 30));
    short y0 = (short)(96 + i * 64);
    SetRect(rr, bx, y0, (short)(bx + bw), (short)(y0 + 56));
}

static void draw_setup_row(Ui *u, int i)
{
    Render *r = u->r;
    Rect    rr;
    int     sel = (i == u->setupSel);
    setup_row_rect(u, i, &rr);
    render_fill(r, &rr, sel ? FILL_SEL : FILL_PANEL);
    render_frame(r, &rr);
    render_text(r, (short)(rr.left + 14), (short)(rr.top + 22), kViewName[i],
                sel ? INK_SELECTED : INK_TITLE);
    render_text(r, (short)(rr.left + 14), (short)(rr.top + 42), kViewDesc[i],
                sel ? INK_SELECTED : INK_DIM);
}

/* The first-run chooser. Returns 1 when it only repainted the selection (the two
 * affected rows, with their union left in u->panelRect for a sub-rect blit), 0 on a
 * full draw — so a Up/Down doesn't reblit the whole welcome screen. */
static int draw_setup(Ui *u)
{
    Render *r = u->r;
    int     W = win_w(u), H = win_h(u);
    Rect    full = u->win->portRect;
    short   cw;
    int     i;

    if (u->setupDrawn && u->lastSetupSel != u->setupSel) {
        Rect a, b;
        render_base_text(r);
        setup_row_rect(u, u->lastSetupSel, &a);
        setup_row_rect(u, u->setupSel,     &b);
        if (u->lastSetupSel >= 0 && u->lastSetupSel < VIEW_N) draw_setup_row(u, u->lastSetupSel);
        draw_setup_row(u, u->setupSel);
        UnionRect(&a, &b, &u->panelRect);
        u->lastSetupSel = u->setupSel;
        return 1;
    }

    render_fill(r, &full, FILL_BG);
    render_base_text(r);
    { const char *t = "Welcome to MacAtrium";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), 40, t, INK_TITLE); }
    { const char *t = "How would you like to browse your library?";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), 64, t, INK_NORMAL); }
    render_hline(r, MARGIN, 76, (short)(W - 2 * MARGIN));

    for (i = 0; i < VIEW_N; i++) draw_setup_row(u, i);

    { const char *t = "Up / Down to choose, Return to continue.";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), (short)(H - 26), t, INK_DIM); }
    { const char *t = "You can change this any time in the View menu.";
      cw = render_text_width(r, t); render_text(r, (short)((W - cw) / 2), (short)(H - 12), t, INK_DIM); }
    u->setupDrawn = 1;
    u->lastSetupSel = u->setupSel;
    return 0;
}

/* Shared browse-screen header: the Settings gear, the centred "^ Category v" band,
 * and the N / M counter (the app title lives in the System menu bar now). Used by
 * the grid view (the carousel draws its own identical header inline). */
static void draw_browse_header(Ui *u)
{
    Render   *r = u->r;
    Model    *m = u->m;
    ModelCat *cat = model_cur_cat(m);
    int       W = win_w(u);
    char      num[16];
    render_base_text(r);
    if (cat) {
        char  cl[ITEM_CAT_LEN + 8];
        short cw, maxw = (short)(2 * (CATBAND_HALF - 28));
        /* the category name in Chicago (the system heading face) — bolder than the
         * Geneva body text; the little-arrows stepper sits at the band's right edge */
        render_sys_text(r);
        strncpy(cl, cat->name, sizeof cl - 1); cl[sizeof cl - 1] = '\0';
        ui_append_disk_tag(u, cat->vol, cl, (int)sizeof cl);   /* [N] when multi-disk (docs/37) */
        while (cl[0] && render_text_width(r, cl) > maxw) cl[strlen(cl) - 1] = '\0';
        cw = render_text_width(r, cl);
        render_text(r, (short)((W - cw) / 2), 20, cl, INK_NORMAL);
        render_base_text(r);                          /* counter back in the body face */
        draw_cat_stepper(u);
        {
            char line[24];
            l2s(m->curItem + 1, num); strcpy(line, num); strcat(line, " / ");
            l2s(cat->count, num); strcat(line, num);
            render_text(r, (short)(W - MARGIN - render_text_width(r, line)), 20, line, INK_DIM);
        }
    }
    render_hline(r, 0, (short)W, (short)(HEADER_H - 1));
}

/* Refresh ONLY the "N / M" counter at the header's right edge (its own erase + draw)
 * — used by the incremental redraws so an item move never repaints the header centre,
 * where the native category steppers live (repainting that whole band, on the direct-
 * draw path or via a header-wide fill, is what erased / flashed the ◀ ▶ buttons). */
#define CTR_W 110
static void draw_browse_counter(Ui *u)
{
    Render   *r = u->r;
    Model    *m = u->m;
    ModelCat *cat = model_cur_cat(m);
    int       W = win_w(u);
    char      num[16], line[24];
    Rect      cr;
    if (!cat) return;
    SetRect(&cr, (short)(W - CTR_W), 2, W, (short)(HEADER_H - 1));
    render_fill(r, &cr, FILL_BG);
    render_base_text(r);
    l2s(m->curItem + 1, num); strcpy(line, num); strcat(line, " / ");
    l2s(cat->count, num); strcat(line, num);
    render_text(r, (short)(W - MARGIN - render_text_width(r, line)), 20, line, INK_DIM);
}

/* Scroll-bar gutter width (the grid/list reserve this column for the real
 * Control-Manager scroll bar; see ui_paint_controls). */
#define SBW 16

/* Split `name` into up to two lines that each fit `maxW`, preferring a word break;
 * the 2nd line is ellipsised if the name is longer than two lines hold. l2[0]=0 when
 * one line is enough. l1/l2 must hold ITEM_NAME_LEN+2. */
static void grid_name_2(Render *r, const char *name, short maxW, char *l1, char *l2)
{
    int  len = (int)strlen(name), fit = 0, sp = -1, i;
    char buf[ITEM_NAME_LEN + 2];
    l1[0] = l2[0] = '\0';
    if (render_text_width(r, name) <= maxW) { strcpy(l1, name); return; }
    for (i = 1; i <= len && i < (int)sizeof buf; i++) {     /* longest prefix that fits */
        memcpy(buf, name, i); buf[i] = '\0';
        if (render_text_width(r, buf) > maxW) break;
        fit = i;
        if (name[i - 1] == ' ') sp = i - 1;
    }
    if (sp > 0) fit = sp;                                   /* prefer a word break */
    memcpy(l1, name, fit); l1[fit] = '\0';
    while (fit > 0 && l1[fit - 1] == ' ') l1[--fit] = '\0';
    {   const char *rest = name + fit;
        while (*rest == ' ') rest++;
        strncpy(l2, rest, ITEM_NAME_LEN); l2[ITEM_NAME_LEN] = '\0';
        if (render_text_width(r, l2) > maxW) {             /* ellipsise the tail */
            int k = (int)strlen(l2);
            while (k > 1) {
                k--;
                memcpy(buf, l2, k); buf[k] = '\xC9'; buf[k + 1] = '\0';   /* 0xC9 = … */
                if (render_text_width(r, buf) <= maxW) break;
            }
            strcpy(l2, buf);
        }
    }
}

/* Blit-list builder: append `content` MINUS the sub-rect `hole` to rects[] (up to
 * four bands around the hole), bumping *n (capped at `cap`). An incremental redraw
 * uses this so the CopyBits that refreshes a changed content region never overwrites
 * a real Control-Manager control (the Launch button) sitting inside it — the control
 * is drawn straight onto the window, not the off-screen buffer, so blitting the
 * buffer over it would erase it and force a flickery redraw. No intersection → the
 * whole `content` is appended. */
static void push_around(Rect *rects, int *n, int cap, const Rect *content, const Rect *hole)
{
    Rect c = *content, hh = *hole, h;
    if (!SectRect(&c, &hh, &h)) { if (*n < cap) rects[(*n)++] = c; return; }
    if (h.top    > c.top    && *n < cap) SetRect(&rects[(*n)++], c.left,  c.top,    c.right, h.top);
    if (h.bottom < c.bottom && *n < cap) SetRect(&rects[(*n)++], c.left,  h.bottom, c.right, c.bottom);
    if (h.left   > c.left   && *n < cap) SetRect(&rects[(*n)++], c.left,  h.top,    h.left,  h.bottom);
    if (h.right  < c.right  && *n < cap) SetRect(&rects[(*n)++], h.right, h.top,    c.right, h.bottom);
}

/* ---- Icon Grid view (Finder "by Icon"): a split pane — icons on the left ~2/3,
 * a detail panel (screenshot + info) on the right ~1/3. ---- */
/* Geometry shared by the grid's draw + click + incremental redraw, so a click and
 * a partial repaint land on the same cell the full draw painted. `scroll` is
 * derived from the selection (keeps it centred/visible). */
typedef struct {
    int   cols, cw, chh, top, vis, n, totRows, scroll, gx0;
    short gridRight;   /* x of the scroll bar (right edge of the icon area) */
    Rect  detail;      /* the right detail panel                            */
} GridLayout;

static void grid_layout(Ui *u, GridLayout *g)
{
    Model    *m = u->m;
    ModelCat *cat = model_cur_cat(m);
    int       W = win_w(u), H = win_h(u), gridW, selRow;
    short     detW = 208;
    if (detW > (short)(W / 2)) detW = (short)(W / 2);
    SetRect(&g->detail, (short)(W - detW), (short)HEADER_H, (short)W, (short)(H - HINT_H));
    g->gridRight = (short)(W - detW - SBW);
    if (u->gridStyle == GRID_TILES) { g->cw = 100; g->chh = 82; }  /* roomy At Ease buttons */
    else                            { g->cw = 80;  g->chh = 66; }  /* Finder: room for 2-line names */
    gridW   = g->gridRight - MARGIN;
    g->cols = gridW / g->cw; if (g->cols < 1) g->cols = 1;
    g->top  = HEADER_H + 8;
    g->vis  = (H - HINT_H - g->top) / g->chh; if (g->vis < 1) g->vis = 1;
    g->n    = cat ? cat->count : 0;
    g->totRows = (g->n + g->cols - 1) / g->cols;
    selRow  = m->curItem / g->cols;
    /* Page-based scroll (like the carousel): the visible page is selRow's screenful,
     * so moving WITHIN a page leaves scroll unchanged -> the incremental redraw kicks
     * in; only crossing a page edge scrolls (a full draw). Re-centering on every move
     * (the old behavior) changed scroll each step -> a full redraw every time. */
    g->scroll = (g->vis > 0) ? (selRow / g->vis) * g->vis : 0;
    if (g->scroll < 0) g->scroll = 0;
    g->gx0 = (short)(MARGIN + (gridW - g->cols * g->cw) / 2);
}

/* The cell rect for item `idx`, or 0 if it isn't on the visible page. */
static int grid_cell_rect(const GridLayout *g, int idx, Rect *cell)
{
    int   vis, rrow, ccol;
    short cx, cy;
    if (idx < 0 || idx >= g->n) return 0;
    vis = idx - g->scroll * g->cols;
    if (vis < 0 || vis >= g->vis * g->cols) return 0;
    rrow = vis / g->cols; ccol = vis % g->cols;
    cx = (short)(g->gx0 + ccol * g->cw);
    cy = (short)(g->top + rrow * g->chh);
    SetRect(cell, cx, cy, (short)(cx + g->cw - 4), (short)(cy + g->chh - 4));
    return 1;
}

/* One grid cell (icon + name), selected highlight or normal. A non-selected fill
 * is FILL_BG so repainting a previously-selected cell erases its highlight. */
static void draw_grid_cell(Ui *u, const GridLayout *g, int idx)
{
    Render        *r = u->r;
    Model         *m = u->m;
    ModelCat      *cat = model_cur_cat(m);
    const CatItem *it;
    Art           *ic;
    Rect           cell, ir;
    char           l1[ITEM_NAME_LEN + 2], l2[ITEM_NAME_LEN + 2];
    const char    *ls[2];
    short          isz = 32, cw, ix, ny;
    int            isSel, nlines, ln, raised;
    if (!cat || !grid_cell_rect(g, idx, &cell)) return;
    it = &m->cat->items[cat->idx[idx]];
    isSel = (idx == m->curItem);
    ic = row_icon(u, cat->idx[idx], it);
    cw = (short)(cell.right - cell.left);
    render_fill(r, &cell, FILL_BG);                        /* erase (handles deselect) */

    /* The raised "At Ease" tile is a sys7/sys8 affordance; sys6 (pre-At-Ease)
     * draws the flat by-icon look instead (docs/36 Phase 3). */
    raised = (u->gridStyle == GRID_TILES && r->look && r->look->tileRaised);
    if (raised) {
        /* At Ease tile: a raised rounded button — a grey (platinum) face with a 1px
         * drop shadow, so it reads as a button, not a white box (Mac HIG button look).
         * The whole tile highlights when selected. */
        Rect tile = cell, sh;
        InsetRect(&tile, 1, 1);
        sh = tile; OffsetRect(&sh, 1, 1);
        render_round_frame(r, &sh);                            /* drop shadow (behind) */
        render_fill(r, &tile, isSel ? FILL_SEL : FILL_TILE);
        render_round_frame(r, &tile);
        ix = (short)(cell.left + (cw - isz) / 2);
        SetRect(&ir, ix, (short)(cell.top + 8), (short)(ix + isz), (short)(cell.top + 8 + isz));
        if (ic) art_draw_fit(ic, &ir); else render_frame(r, &ir);
        grid_name_2(r, it->name, (short)(cw - 10), l1, l2);
        ny = (short)(cell.top + 8 + isz + 13);
    } else {
        /* Finder by-icon: icon, 2-line centred name; the NAME highlights when
         * selected (a tight inverse behind each line), not the whole cell. */
        ix = (short)(cell.left + (cw - isz) / 2);
        SetRect(&ir, ix, (short)(cell.top + 4), (short)(ix + isz), (short)(cell.top + 4 + isz));
        if (ic) art_draw_fit(ic, &ir); else render_frame(r, &ir);
        grid_name_2(r, it->name, (short)(cw - 2), l1, l2);
        ny = (short)(cell.top + 4 + isz + 12);
    }

    ls[0] = l1; ls[1] = l2; nlines = l2[0] ? 2 : 1;
    for (ln = 0; ln < nlines; ln++, ny = (short)(ny + 12)) {
        short tw = render_text_width(r, ls[ln]);
        short lx = (short)(cell.left + (cw - tw) / 2);
        if (isSel && !raised) {                            /* flat path highlights the name */
            Rect hl;
            SetRect(&hl, (short)(lx - 2), (short)(ny - 10), (short)(lx + tw + 2), (short)(ny + 2));
            render_fill(r, &hl, FILL_SEL);
        }
        render_text(r, lx, ny, ls[ln], isSel ? INK_SELECTED : INK_NORMAL);
    }

    if (it->cdImage[0]) draw_cd_badge(r, &cell);   /* CD-title marker (docs/45) */
}

/* The detail panel's cover box (screenshot, 4:3) and its Launch-button rect, shared
 * by the full draw, the incremental redraw, and ui_paint_controls so the drawn pixels
 * and the control placement can never drift apart. */
static void grid_art_rect(const GridLayout *g, Rect *art)
{
    short pad = MARGIN;
    short aw  = (short)((g->detail.right - g->detail.left) - 2 * pad);
    short ah  = (short)(aw * 3 / 4);
    SetRect(art, (short)(g->detail.left + pad), (short)(g->detail.top + pad),
            (short)(g->detail.left + pad + aw), (short)(g->detail.top + pad + ah));
}
static void grid_launch_rect(const GridLayout *g, Rect *lb)
{
    SetRect(lb, (short)(g->detail.left + MARGIN + 24), (short)(g->detail.bottom - 30),
            (short)(g->detail.right - MARGIN - 24), (short)(g->detail.bottom - 8));
}

/* The right detail panel: a left divider, the selected item's screenshot, then its
 * name / year-vendor / genre / blurb (mirrors the carousel's detail band). */
static void draw_grid_detail(Ui *u, const GridLayout *g)
{
    Render        *r = u->r;
    const CatItem *cur = model_cur_item(u->m);
    Rect           d = g->detail, art, dv;
    short          pad = MARGIN, aw, tx, ty;
    char           num[16];

    render_fill(r, &d, FILL_BG);
    SetRect(&dv, d.left, d.top, (short)(d.left + 1), d.bottom);
    render_frame(r, &dv);
    render_base_text(r);

    grid_art_rect(g, &art);
    aw = (short)(art.right - art.left);           /* the blurb wraps to the cover's width */
    draw_detail_art(u, &art);
    if (!cur) return;

    tx = (short)(d.left + pad);
    ty = (short)(art.bottom + 16);
    render_text(r, tx, ty, cur->name, INK_TITLE); ty = (short)(ty + ROW_H + 3);
    {   char buf[ITEM_VENDOR_LEN + 24]; buf[0] = '\0';
        if (cur->year > 0) { l2s(cur->year, num); strcat(buf, num); }
        if (cur->vendor[0]) { if (buf[0]) strcat(buf, " - "); strncat(buf, cur->vendor, sizeof buf - strlen(buf) - 1); }
        if (buf[0]) { render_text(r, tx, ty, buf, INK_DIM); ty = (short)(ty + ROW_H); }
    }
    if (cur->genre[0]) {
        char gg[ITEM_GENRE_LEN + 8]; strcpy(gg, "Genre: "); strncat(gg, cur->genre, ITEM_GENRE_LEN);
        render_text(r, tx, ty, gg, INK_DIM); ty = (short)(ty + ROW_H);
    }
    ty = (short)(ty + 6);
    if (u->status[0])      render_text(r, tx, ty, u->status, INK_NORMAL);
    else if (cur->desc[0]) draw_wrapped(r, tx, ty, aw, ROW_H, cur->desc, INK_NORMAL, 6);
    /* the bottom ~36px is reserved for the real Launch button (ui_paint_controls) */
}

static void draw_iconview(Ui *u)
{
    Render     *r = u->r;
    ModelCat   *cat = model_cur_cat(u->m);
    Rect        full = u->win->portRect;
    int         H = win_h(u), i;
    GridLayout  g;

    render_fill(r, &full, FILL_BG);
    draw_browse_header(u);
    grid_layout(u, &g);
    if (!cat || cat->count == 0) {
        const char *t = "(no items in this category)";
        render_text(r, (short)((g.gridRight - render_text_width(r, t)) / 2), (short)(H / 2), t, INK_DIM);
    } else {
        for (i = 0; i < g.vis * g.cols; i++) {
            int idx = g.scroll * g.cols + i;
            if (idx >= g.n) break;
            draw_grid_cell(u, &g, idx);
        }
        /* the scroll-bar gutter (g.gridRight..+SBW) is owned by the real control */
    }
    draw_grid_detail(u, &g);
    {
        static const HintGroup fg[] = {
            {"<", ">", "Move"}, {"^", "v", 0}, {"ret", 0, "Play"},
            {"A-Z", 0, "Find"}, {"esc", 0, "Menu"}
        };
        draw_browse_footer(u, fg, 5);
    }
    u->lastDrawnItem = u->m->curItem;
    u->lastDrawnTop  = g.scroll;
    u->lastDrawnCat  = u->m->curCat;
}

static int iconview_nav(Ui *u, char ch)
{
    Model      *m = u->m;
    GridLayout  g;
    int         idx = m->curItem;
    grid_layout(u, &g);
    switch (ch) {
        case kCharLeft:  model_move_item(m, -1); return 1;
        case kCharRight: model_move_item(m, +1); return 1;
        case kCharUp:
            if (idx < g.cols) { if (!model_move_cat(m, -1)) u->settingsFocus = 1; }
            else model_move_item(m, -g.cols);
            return 1;
        case kCharDown:
            if (idx + g.cols >= g.n) model_move_cat(m, +1);
            else model_move_item(m, +g.cols);
            return 1;
    }
    return 0;
}

/* Click a grid cell: select it; re-click the already-selected cell launches it
 * (so a double-click = select-then-launch, the native open-on-double-click feel). */
static int iconview_click(Ui *u, Point pt, UiCommand *out)
{
    GridLayout g;
    int        i, W = win_w(u);
    short      midX = (short)(W / 2);
    Rect       band;
    SetRect(&band, (short)(midX - CATBAND_HALF), 2, (short)(midX + CATBAND_HALF), (short)(HEADER_H - 2));
    if (PtInRect(pt, &band)) {                        /* "^ Category v" header band */
        model_move_cat(u->m, pt.h < midX ? -1 : +1);
        return 1;
    }
    grid_layout(u, &g);
    if (g.n == 0) return 0;
    for (i = 0; i < g.vis * g.cols; i++) {
        int  idx = g.scroll * g.cols + i;
        Rect cell;
        if (idx >= g.n) break;
        if (grid_cell_rect(&g, idx, &cell) && PtInRect(pt, &cell)) {
            if (idx == u->m->curItem) { u->status[0] = '\0'; *out = UI_LAUNCH; }
            else model_move_item(u->m, idx - u->m->curItem);
            return 1;
        }
    }
    return 0;
}

/* Incremental selection redraw: if the move stayed on the drawn page (same scroll +
 * category), repaint just the old + new cell + the detail panel and blit that union
 * — not the whole window + every icon. Returns 0 (caller does a full draw) when the
 * page scrolled or the category changed. */
static int iconview_draw_sel(Ui *u)
{
    GridLayout g;
    Rect       old, neu, body, counter;
    if (!u->bgValid) return 0;
    grid_layout(u, &g);
    if (g.scroll != u->lastDrawnTop || u->m->curCat != u->lastDrawnCat) return 0;
    render_begin(u->r, u->win);
    draw_browse_counter(u);                     /* only the N/M counter — not the steppers */
    draw_grid_cell(u, &g, u->lastDrawnItem);    /* old -> deselected */
    draw_grid_cell(u, &g, u->m->curItem);       /* new -> selected   */
    draw_grid_detail(u, &g);
    if (!grid_cell_rect(&g, u->lastDrawnItem, &old)) old = g.detail;
    if (!grid_cell_rect(&g, u->m->curItem, &neu)) neu = g.detail;
    /* Blit the two changed cells and the detail panel — the detail split around the
     * Launch button (a real control drawn onto the window, not the buffer) so the copy
     * never erases it. Cells stay left of the scroll-bar gutter, the detail right of
     * it; the N/M counter goes too, never the header centre (the category steppers). */
    {
        Rect rects[8], lb;
        int  nr = 0;
        UnionRect(&old, &neu, &body);                    /* the two cells (left of the gutter) */
        if (body.top < HEADER_H) body.top = HEADER_H;
        rects[nr++] = body;
        grid_launch_rect(&g, &lb);
        push_around(rects, &nr, 7, &g.detail, &lb);
        SetRect(&counter, (short)(win_w(u) - CTR_W), 0, (short)win_w(u), (short)HEADER_H);
        rects[nr++] = counter;
        render_end_rects(u->r, u->win, rects, nr);
    }
    u->lastDrawnItem = u->m->curItem;
    return 1;
}

/* Deferred screenshot settled: repaint ONLY the cover box (not the whole panel — that
 * re-rendered the name / blurb and clobbered the Launch button on every art load). */
static void iconview_draw_art(Ui *u)
{
    GridLayout g;
    Rect       art;
    if (!u->bgValid) return;
    grid_layout(u, &g);
    grid_art_rect(&g, &art);
    render_begin(u->r, u->win);
    draw_detail_art(u, &art);
    render_end_rect(u->r, u->win, &art);
}

static int iconview_idle(Ui *u) { return ensure_art_loaded(u) ? UI_IDLE_ART : UI_IDLE_NONE; }

/* ---- List / two-pane browser view ---- */
#define LPANE 152   /* categories pane width */
#define LDET  90    /* bottom detail (screenshot) strip height */

static void vbar(Ui *u, short x, short y, short h)   /* 1px vertical divider */
{
    Rect d; SetRect(&d, x, y, (short)(x + 1), (short)(y + h)); render_frame(u->r, &d);
}

/* Geometry shared by the list's draw + click: the two panes' visible-row windows
 * (first index + row count) and the strip bounds, so a click lands on the same row
 * the draw painted. */
typedef struct {
    short bTop, bBot, lstBot, rx, rw;
    short catW;                /* categories pane content width (narrowed for its scroll bar) */
    int   catRows, catTop;     /* categories pane: visible rows + first index */
    int   itemRows, itemTop;   /* items pane: visible rows + first index      */
    int   nItems;
} ListLayout;

static void list_col_x(Ui *u, short *nameX, short *typeX, short *yearX);   /* fwd */

/* Both panes scroll on an INDEPENDENT view offset (u->listCatTop / u->listItemTop),
 * not derived from the selection — a real Mac list where the scroll bar moves the view
 * and the selection can sit anywhere (even off-screen). The offset is clamped to a valid
 * range here and written back, so a category change or resize can't leave it dangling. */
static void list_layout(Ui *u, ListLayout *L)
{
    Model    *m = u->m;
    ModelCat *cat = model_cur_cat(m);
    int       W = win_w(u), H = win_h(u);
    int       rows, top, n;
    L->bTop   = (short)HEADER_H;
    L->bBot   = (short)(H - HINT_H);
    L->lstBot = (short)(L->bBot - LDET);
    L->rx     = (short)(LPANE + 1);
    L->rw     = (short)(W - LPANE - 1);
    /* categories pane */
    rows = (L->bBot - (L->bTop + 24)) / ROW_H; if (rows < 1) rows = 1; n = m->ncats;
    top = u->listCatTop; if (top > n - rows) top = n - rows; if (top < 0) top = 0;
    u->listCatTop = top;
    L->catRows = rows; L->catTop = top;
    L->catW = (short)((n > rows) ? (LPANE - SBW) : LPANE);   /* room for the cat scroll bar */
    /* items pane */
    n = cat ? cat->count : 0;
    rows = (L->lstBot - (L->bTop + 24)) / ROW_H; if (rows < 1) rows = 1;
    top = u->listItemTop; if (top > n - rows) top = n - rows; if (top < 0) top = 0;
    u->listItemTop = top;
    L->itemRows = rows; L->itemTop = top; L->nItems = n;
}

/* Scroll a pane so the current selection is visible (called after a keyboard move,
 * which drives the selection; the view follows just enough to keep it on-screen). */
static void list_reveal_item(Ui *u)
{
    ListLayout L; list_layout(u, &L);
    if (u->m->curItem < L.itemTop)                    u->listItemTop = u->m->curItem;
    else if (u->m->curItem >= L.itemTop + L.itemRows) u->listItemTop = u->m->curItem - L.itemRows + 1;
}
static void list_reveal_cat(Ui *u)
{
    ListLayout L; list_layout(u, &L);
    if (u->m->curCat < L.catTop)                    u->listCatTop = u->m->curCat;
    else if (u->m->curCat >= L.catTop + L.catRows)  u->listCatTop = u->m->curCat - L.catRows + 1;
}

/* One categories-pane row (visible index i). Selected + focused = filled; selected
 * but the OTHER pane is focused = outline only; clears its row first (for redraw). */
static void draw_list_cat_row(Ui *u, const ListLayout *L, int i)
{
    Render *r = u->r;
    Model  *m = u->m;
    int     ci = L->catTop + i, sel, active;
    short   y0;
    Rect    rr;
    char    nm[ITEM_CAT_LEN];
    if (i < 0 || ci < 0 || ci >= m->ncats) return;
    sel = (ci == m->curCat); active = (u->listFocus == 0);
    y0 = (short)(L->bTop + 26 + i * ROW_H);
    SetRect(&rr, 1, y0, (short)(L->catW - 1), (short)(y0 + ROW_H));
    render_fill(r, &rr, FILL_BG);
    if (sel) { if (active) render_fill(r, &rr, FILL_SEL); else render_frame(r, &rr); }
    strncpy(nm, m->cats[ci].name, sizeof nm - 1); nm[sizeof nm - 1] = '\0';
    ui_append_disk_tag(u, m->cats[ci].vol, nm, (int)sizeof nm);   /* [N] when multi-disk (docs/37) */
    while (nm[0] && render_text_width(r, nm) > L->catW - 14) nm[strlen(nm) - 1] = '\0';
    render_text(r, 8, (short)(y0 + ROW_H - 5), nm, (sel && active) ? INK_SELECTED : INK_NORMAL);
}

/* One items-pane row (visible index i): name + genre + year columns, same focus-
 * aware highlight as the category rows. */
static void draw_list_item_row(Ui *u, const ListLayout *L, int i)
{
    Render        *r = u->r;
    Model         *m = u->m;
    ModelCat      *cat = model_cur_cat(m);
    const CatItem *it;
    int            idx = L->itemTop + i, sel, active, ink, dim;
    int            W = win_w(u);
    short          y0;
    Rect           rr;
    char           nm[ITEM_NAME_LEN], g[48], num[16];
    if (!cat || i < 0 || idx < 0 || idx >= L->nItems) return;
    it = &m->cat->items[cat->idx[idx]];
    sel = (idx == m->curItem); active = (u->listFocus == 1);
    y0 = (short)(L->bTop + 26 + i * ROW_H);
    SetRect(&rr, L->rx, y0, (short)(W - SBW), (short)(y0 + ROW_H));
    render_fill(r, &rr, FILL_BG);
    if (sel) { if (active) render_fill(r, &rr, FILL_SEL); else render_frame(r, &rr); }
    ink = (sel && active) ? INK_SELECTED : INK_NORMAL;
    dim = (sel && active) ? INK_SELECTED : INK_DIM;
    {   short nameX, typeX, yearX, base = (short)(y0 + ROW_H - 5);
        list_col_x(u, &nameX, &typeX, &yearX);             /* draggable Name|Type divider */
        strncpy(nm, it->name, sizeof nm - 1); nm[sizeof nm - 1] = '\0';
        while (nm[0] && render_text_width(r, nm) > typeX - L->rx - 14) nm[strlen(nm) - 1] = '\0';
        render_text(r, (short)(L->rx + 8), base, nm, ink);
        strncpy(g, it->genre, sizeof g - 1); g[sizeof g - 1] = '\0';
        while (g[0] && render_text_width(r, g) > yearX - typeX - 6) g[strlen(g) - 1] = '\0';
        if (g[0]) render_text(r, typeX, base, g, dim);
        if (it->year > 0) { l2s(it->year, num); render_text(r, yearX, base, num, dim); }
    }
}

/* The detail strip's cover box (screenshot, 4:3) and its Launch-button rect, shared
 * by the strip draw, the incremental redraw, and ui_paint_controls so the drawn pixels
 * and the control placement stay in lockstep. */
static void list_art_rect(const ListLayout *L, Rect *ar)
{
    short ay0 = (short)(L->lstBot + 8), ah = (short)(LDET - 18), aw = (short)(ah * 4 / 3);
    SetRect(ar, (short)(L->rx + 12), ay0, (short)(L->rx + 12 + aw), (short)(ay0 + ah));
}
static void list_launch_rect(Ui *u, const ListLayout *L, Rect *lb)
{
    int W = win_w(u);
    SetRect(lb, (short)(W - 96), (short)(L->lstBot + 46), (short)(W - 12), (short)(L->lstBot + 66));
}
/* Draw just the cover into `ar`: erase, frame, then the screenshot (or an empty frame
 * until it loads). Shared by the strip's full draw and the deferred-art repaint so
 * both land the cover identically. */
static void list_draw_cover(Ui *u, const Rect *ar)
{
    const CatItem *cur = model_cur_item(u->m);
    int   loaded = (cur && cur == u->artFor);
    Rect  in = *ar;
    render_fill(u->r, &in, FILL_BG);
    render_frame(u->r, ar);
    if (loaded && u->listArt) { InsetRect(&in, 2, 2); art_draw_fit(u->listArt, &in); }
}

/* The bottom detail strip — the selected item's screenshot + name / year / genre. */
static void draw_list_detail(Ui *u, const ListLayout *L)
{
    Render        *r = u->r;
    const CatItem *cur;
    int            W = win_w(u);
    short          mx;
    Rect           strip, ar;
    char           num[16];
    cur = model_cur_item(u->m);   /* cover: pre-loaded by a full draw, deferred by an in-page move */
    SetRect(&strip, L->rx, L->lstBot, (short)W, L->bBot);
    render_fill(r, &strip, FILL_BG);
    render_base_text(r);
    render_hline(r, L->rx, (short)W, L->lstBot);
    list_art_rect(L, &ar);
    mx = (short)(ar.right + 14);
    list_draw_cover(u, &ar);
    if (cur) {
        char meta[ITEM_GENRE_LEN + 32]; meta[0] = '\0';
        render_text(r, mx, (short)(L->lstBot + 22), cur->name, INK_TITLE);
        if (cur->year > 0) { l2s(cur->year, num); strcat(meta, num); strcat(meta, "  -  "); }
        if (cur->genre[0]) strcat(meta, cur->genre);
        render_text(r, mx, (short)(L->lstBot + 40), meta, INK_NORMAL);
        /* controls now live in the shared footer (draw_browse_footer) */
    }
}

/* The clickable column-header positions (X of Name / Type / Year) — shared by the
 * header draw and the click hit-test so they can't drift. */
static void list_col_x(Ui *u, short *nameX, short *typeX, short *yearX)
{
    int W = win_w(u);
    if (u->listColType < 60)  u->listColType = 60;     /* keep both columns usable */
    if (u->listColType > 260) u->listColType = 260;
    *nameX = (short)(LPANE + 1 + 8);
    *typeX = (short)(W - SBW - u->listColType);         /* draggable Name|Type divider */
    *yearX = (short)(W - SBW - 40);
}

/* Sortable column headers (Name / Type / Year); the active sort column is titled +
 * carries an asc/desc arrow. */
static void draw_list_headers(Ui *u, const ListLayout *L)
{
    Render *r = u->r;
    int     W = win_w(u), i;
    short   y = (short)(L->bTop + 15);
    short   xs[3];
    const char *lbl[3] = { "Name", "Type", "Year" };
    int     modes[3] = { SORT_NAME, SORT_TYPE, SORT_YEAR };
    list_col_x(u, &xs[0], &xs[1], &xs[2]);
    for (i = 0; i < 3; i++) {
        int active = (u->sortMode == modes[i]);
        render_text(r, xs[i], y, lbl[i], active ? INK_TITLE : INK_DIM);
        if (active) {
            short aw = render_text_width(r, lbl[i]);
            Rect  ab;
            SetRect(&ab, (short)(xs[i] + aw + 3), (short)(y - 9), (short)(xs[i] + aw + 11), (short)(y - 1));
            render_arrow(r, &ab, u->sortDesc ? 3 : 2);       /* 2 = asc (up), 3 = desc (down) */
        }
    }
}

/* Rebuild the current page for the active sort + name filter: reset the index from
 * the resident page (no file re-read), re-sort, then narrow by u->filter. Paged mode
 * only (legacy keeps all items resident with category-specific idx[]). */
static void ui_filter_apply(Ui *u)
{
    if (!u->m->loader) return;
    model_set_page(u->m, u->m->cat);                  /* idx -> identity from the page */
    model_sort_page(u->m, u->sortMode, u->sortDesc);
    if (u->filter[0]) model_filter_page(u->m, u->filter);
    ui_page_changed(u);                               /* selection/page changed -> drop art caches */
    u->bgValid = 0;
}

/* Drop an active name filter and restore the full (sorted) page. */
static void ui_filter_clear(Ui *u)
{
    if (!u->filter[0]) return;
    u->filter[0] = '\0';
    ui_filter_apply(u);
}

static void draw_listview(Ui *u)
{
    Render        *r = u->r;
    Model         *m = u->m;
    ModelCat      *cat = model_cur_cat(m);
    int            W = win_w(u), i;
    ListLayout     L;
    Rect           full = u->win->portRect;

    list_layout(u, &L);
    render_fill(r, &full, FILL_BG);
    render_base_text(r);   /* Settings button (header left) is a real control (ui_paint_controls) */
    render_hline(r, 0, (short)W, (short)(HEADER_H - 1));
    vbar(u, LPANE, L.bTop, (short)(L.bBot - L.bTop));

    render_text(r, 8, (short)(L.bTop + 15), "Categories", INK_TITLE);
    render_hline(r, 0, LPANE, (short)(L.bTop + 22));
    for (i = 0; i < L.catRows && L.catTop + i < m->ncats; i++)
        draw_list_cat_row(u, &L, i);

    if (u->filter[0]) {                            /* active filter replaces the headers */
        char fb[40], cb[16];
        strcpy(fb, "Filter: "); strncat(fb, u->filter, 24);
        render_text(r, (short)(L.rx + 8), (short)(L.bTop + 15), fb, INK_TITLE);
        l2s(L.nItems, cb);
        { char cc[20]; strcpy(cc, cb); strcat(cc, " found");
          render_text(r, (short)(W - SBW - render_text_width(r, cc) - 4), (short)(L.bTop + 15), cc, INK_DIM); }
    } else {
        draw_list_headers(u, &L);
    }
    render_hline(r, L.rx, (short)W, (short)(L.bTop + 22));
    if (cat && cat->count > 0) {
        for (i = 0; i < L.itemRows && L.itemTop + i < L.nItems; i++)
            draw_list_item_row(u, &L, i);
        /* the scroll-bar gutter (W-SBW..W) is owned by the real control */
    }
    if (!u->filter[0]) {                            /* the draggable Name|Type divider */
        short nameX, typeX, yearX;
        list_col_x(u, &nameX, &typeX, &yearX);
        vbar(u, (short)(typeX - 6), L.bTop, (short)(L.lstBot - L.bTop));
    }
    draw_list_detail(u, &L);
    {
        static const HintGroup fg[] = {
            {"^", "v", "Move"}, {"<", ">", "Pane"}, {"ret", 0, "Play"},
            {"A-Z", 0, "Find"}, {"esc", 0, "Menu"}
        };
        draw_browse_footer(u, fg, 5);
    }

    u->lastDrawnItem   = m->curItem;
    u->lastDrawnTop    = L.itemTop;
    u->lastDrawnCat    = m->curCat;
    u->lastDrawnCatTop = L.catTop;
    u->lastDrawnFocus  = u->listFocus;
}

/* Left/Right move focus between the two panes (Left at the categories pane reaches
 * the gear, as before); Up/Down move the selection within the focused pane, and the
 * view auto-scrolls just enough to keep the new selection visible (a real list). A new
 * category resets the items view to the top. */
static int listview_nav(Ui *u, char ch)
{
    Model *m = u->m;
    switch (ch) {
        case kCharUp:
            if (u->listFocus == 0) { u->filter[0] = '\0';   /* a new category reloads unfiltered */
                                     if (!model_move_cat(m, -1)) u->settingsFocus = 1;
                                     else { u->listItemTop = 0; list_reveal_cat(u); } }
            else                   { model_move_item(m, -1); list_reveal_item(u); }
            return 1;
        case kCharDown:
            if (u->listFocus == 0) { u->filter[0] = '\0';
                                     if (model_move_cat(m, +1)) { u->listItemTop = 0; list_reveal_cat(u); } }
            else                   { model_move_item(m, +1); list_reveal_item(u); }
            return 1;
        case kCharLeft:
            if (u->listFocus == 1)   u->listFocus = 0;       /* items -> categories */
            else                     u->settingsFocus = 1;   /* categories -> gear  */
            return 1;
        case kCharRight:
            if (u->listFocus == 0)   u->listFocus = 1;       /* categories -> items */
            return 1;
    }
    return 0;
}
/* List screenshot loads deferred: a targeted repaint of just the detail strip. */
static int listview_idle(Ui *u) { return ensure_art_loaded(u) ? UI_IDLE_ART : UI_IDLE_NONE; }

/* Click in the List view: a click in the categories pane selects that category and
 * focuses it; a click in the items pane selects that item and focuses the items
 * pane (re-click the selected item launches it). */
static int listview_click(Ui *u, Point pt, UiCommand *out)
{
    Model      *m = u->m;
    ListLayout  L;
    int         i;
    short       nameX, typeX, yearX, d;
    list_layout(u, &L);
    list_col_x(u, &nameX, &typeX, &yearX);
    /* Grab the Name|Type divider (within 5px, anywhere down the items) and drag it —
     * a standard XOR feedback line that follows the mouse; on release the columns
     * relay out. (No filter active: the header then shows the columns, not the query.) */
    d = (short)(pt.h - typeX);
    if (!u->filter[0] && pt.v >= L.bTop && pt.v < L.lstBot && d >= -5 && d <= 5) {
        short minX = (short)(L.rx + 80), maxX = (short)(yearX - 30), curX = typeX, nx;
        Point mp;
        PenMode(patXor); PenSize(1, 1);
        MoveTo(curX, L.bTop); LineTo(curX, L.lstBot);          /* initial feedback line */
        while (StillDown()) {
            GetMouse(&mp);                                      /* window-local */
            nx = mp.h;
            if (nx < minX) nx = minX;
            if (nx > maxX) nx = maxX;
            if (nx != curX) {
                MoveTo(curX, L.bTop); LineTo(curX, L.lstBot);  /* erase old */
                MoveTo(nx,   L.bTop); LineTo(nx,   L.lstBot);  /* draw new */
                curX = nx;
            }
        }
        MoveTo(curX, L.bTop); LineTo(curX, L.lstBot);          /* erase final */
        PenNormal();
        u->listColType = (win_w(u) - SBW) - curX;              /* new divider offset */
        u->lastDrawnCat = -1;                                  /* force a full list redraw */
        return 1;
    }
    if (pt.h >= L.rx && pt.v >= L.bTop && pt.v < (short)(L.bTop + 24)) {  /* column header → sort */
        int   mode;
        mode = (pt.h >= yearX) ? SORT_YEAR : (pt.h >= typeX) ? SORT_TYPE : SORT_NAME;
        if (u->sortMode == mode) u->sortDesc = !u->sortDesc;   /* same column: flip direction */
        else { u->sortMode = mode; u->sortDesc = 0; }
        model_sort_page(m, u->sortMode, u->sortDesc);
        u->lastDrawnCat = -1;                                  /* force a full list redraw */
        return 1;
    }
    if (pt.h < LPANE) {                                  /* categories pane */
        for (i = 0; i < L.catRows && L.catTop + i < m->ncats; i++) {
            int   ci = L.catTop + i;
            short y0 = (short)(L.bTop + 26 + i * ROW_H);
            Rect  rr; SetRect(&rr, 1, y0, (short)(L.catW - 1), (short)(y0 + ROW_H));
            if (PtInRect(pt, &rr)) {
                u->listFocus = 0;
                if (ci != m->curCat) { u->filter[0] = '\0'; model_move_cat(m, ci - m->curCat);
                                       u->listItemTop = 0; }   /* new category -> items view to top */
                return 1;
            }
        }
        return 0;
    }
    if (pt.v < L.lstBot) {                               /* items pane */
        for (i = 0; i < L.itemRows && L.itemTop + i < L.nItems; i++) {
            int   idx = L.itemTop + i;
            short y0 = (short)(L.bTop + 26 + i * ROW_H);
            Rect  rr; SetRect(&rr, L.rx, y0, (short)(win_w(u) - SBW), (short)(y0 + ROW_H));
            if (PtInRect(pt, &rr)) {
                u->listFocus = 1;
                if (idx == m->curItem) { u->status[0] = '\0'; *out = UI_LAUNCH; }
                else model_move_item(m, idx - m->curItem);
                return 1;
            }
        }
    }
    return 0;
}

/* Incremental redraw for an items-pane selection move that stayed on the visible
 * page: repaint just the old + new item rows + the detail strip, blit the items
 * side. A category change, a focus change, or a scroll falls back to a full draw. */
static int listview_draw_sel(Ui *u)
{
    ListLayout L;
    if (!u->bgValid) return 0;
    list_layout(u, &L);
    if (u->listFocus != 1 || u->m->curCat != u->lastDrawnCat ||
        u->listFocus != u->lastDrawnFocus || L.itemTop != u->lastDrawnTop)
        return 0;
    render_begin(u->r, u->win);
    draw_list_item_row(u, &L, u->lastDrawnItem - L.itemTop);   /* old -> deselected */
    draw_list_item_row(u, &L, u->m->curItem - L.itemTop);      /* new -> selected   */
    draw_list_detail(u, &L);
    /* Blit the two changed rows and the detail strip — the strip split around the
     * Launch button (a real control on the window) so the copy never erases it. Rows
     * stay left of the scroll-bar gutter; the strip sits below the gutter. */
    {
        Rect  rects[8], row, strip, lb;
        int   nr = 0, W = win_w(u);
        short y0o = (short)(L.bTop + 26 + (u->lastDrawnItem - L.itemTop) * ROW_H);
        short y0n = (short)(L.bTop + 26 + (u->m->curItem   - L.itemTop) * ROW_H);
        SetRect(&row, L.rx, y0o, (short)(W - SBW), (short)(y0o + ROW_H)); rects[nr++] = row;
        SetRect(&row, L.rx, y0n, (short)(W - SBW), (short)(y0n + ROW_H)); rects[nr++] = row;
        SetRect(&strip, L.rx, L.lstBot, (short)W, L.bBot);
        list_launch_rect(u, &L, &lb);
        push_around(rects, &nr, 8, &strip, &lb);
        render_end_rects(u->r, u->win, rects, nr);
    }
    u->lastDrawnItem = u->m->curItem;
    return 1;
}

/* Deferred screenshot settled: repaint ONLY the cover box (not the whole strip — that
 * re-rendered the name / meta and clobbered the Launch button on every art load). */
static void listview_draw_art(Ui *u)
{
    ListLayout L;
    Rect       ar;
    if (!u->bgValid) return;
    list_layout(u, &L);
    list_art_rect(&L, &ar);
    render_begin(u->r, u->win);
    list_draw_cover(u, &ar);              /* idle (ui_idle) already loaded the cover */
    render_end_rect(u->r, u->win, &ar);
}

/* ---- browse views (MVC strategy) ----------------------------------------
 * Each view renders the shared Model (model.c) in the content area and maps the
 * arrow keys to model moves. The shared keys (Return / Esc / P / I / type-ahead)
 * and the chrome live in ui.c, so a view is just: draw + arrow-nav + mouse-click +
 * deferred-art. */
typedef struct {
    const char *name;
    void (*draw)(Ui *u);
    int  (*nav)(Ui *u, char ch);              /* arrow key → model move; 1 = consumed */
    int  (*idle)(Ui *u);                      /* deferred art load → UI_IDLE_* */
    int  (*click)(Ui *u, Point pt, UiCommand *out); /* hit-test; 1 = handled (*out cmd) */
    int  (*draw_sel)(Ui *u);                  /* incremental selection redraw; 1 = done */
    void (*draw_art)(Ui *u);                  /* targeted detail-art repaint (UI_IDLE_ART) */
} BrowseView;

static int carousel_nav(Ui *u, char ch)
{
    switch (ch) {
        case kCharLeft:  model_move_item(u->m, -1); return 1;   /* scroll games */
        case kCharRight: model_move_item(u->m, +1); return 1;
        case kCharUp:    if (!model_move_cat(u->m, -1)) u->settingsFocus = 1; return 1;
        case kCharDown:  model_move_cat(u->m, +1); return 1;    /* change category */
    }
    return 0;
}
static int carousel_idle(Ui *u) { return ensure_art_loaded(u) ? UI_IDLE_ART : UI_IDLE_NONE; }

/* Carousel deferred cover settled: repaint only the detail cover box (the direct-
 * draw path; the off-screen path already loaded it in draw_carousel). */
static void carousel_draw_art(Ui *u)
{
    CarLayout L;
    Rect      ar;
    render_begin(u->r, u->win);
    carousel_layout(u, &L);
    detail_art_rect(&L, &ar);
    draw_detail_art(u, &ar);
    render_end_rect(u->r, u->win, &ar);   /* only the cover box, never the Launch button */
}

/* Incremental selection redraw: an in-page ←/→ move repaints only the old + new
 * tile, the centred name strip, the header counter, and the detail band — and blits
 * that union, not the whole window. Returns 0 (the caller does a full draw) when the
 * page or category changed, i.e. a full screenful scrolls in. */
static int carousel_draw_sel(Ui *u)
{
    CarLayout L;
    Rect      oldB, newB, nameBand, det, body, counter;
    int       oldSlot;
    if (!u->bgValid) return 0;
    carousel_layout(u, &L);
    if (!L.hasItems) return 0;
    if (u->m->curCat != u->lastDrawnCat) return 0;
    if (L.page != u->lastDrawnTop)        return 0;   /* paged -> full draw */
    oldSlot = u->lastDrawnItem - L.first;
    if (oldSlot < 0 || oldSlot >= L.nTiles) return 0; /* belt + braces */

    render_begin(u->r, u->win);
    if (u->r->useOffscreen) ensure_art_loaded(u);  /* carousel keeps its one-pass cover (atomic move) */
    draw_browse_counter(u);                     /* only the N/M counter — not the steppers */

    draw_carousel_tile(u, &L, oldSlot);        /* old -> deselected */
    draw_carousel_tile(u, &L, L.selOnPage);    /* new -> selected   */

    carousel_name_band(&L, &nameBand);
    render_fill(u->r, &nameBand, FILL_BG);
    {
        const CatItem *cur = model_cur_item(u->m);
        if (cur) {
            short nw = render_text_width(u->r, cur->name);
            render_text(u->r, (short)(L.clx + (win_w(u) - L.clx - nw) / 2),
                        L.nameBase, cur->name, INK_TITLE);
        }
    }

    draw_carousel_detail(u, &L);

    carousel_tile_box(&L, oldSlot,     0, &oldB);   /* col rects bound the selection box */
    carousel_tile_box(&L, L.selOnPage, 0, &newB);
    SetRect(&det, L.clx, L.detTop, (short)win_w(u), L.detBot);
    /* Blit the changed regions as separate bands that straddle — but never cover — the
     * Launch button and the ◀▶ pager (real controls drawn onto the window): the tiles
     * sit above the Launch button, the name band between it and the pager, the detail
     * band below the pager. Copying over either erases it and forces a flickery
     * redraw. The N/M counter goes too; the header centre (steppers) never does. */
    {
        Rect rects[4];
        UnionRect(&oldB, &newB, &body);                 /* just the two tile columns */
        if (body.top < HEADER_H) body.top = HEADER_H;
        if (body.bottom > L.launchBtn.top) body.bottom = L.launchBtn.top;  /* stay above Launch */
        SetRect(&counter, (short)(win_w(u) - CTR_W), 0, (short)win_w(u), (short)HEADER_H);
        rects[0] = body; rects[1] = nameBand; rects[2] = det; rects[3] = counter;
        render_end_rects(u->r, u->win, rects, 4);
    }
    u->lastDrawnItem = u->m->curItem;
    return 1;
}

/* Click in the carousel: the "^ cat v" band changes category; a visible tile selects
 * it (re-clicking the selected tile launches it — the native open-on-double-click
 * feel). The Launch button + the ◀▶ pager are real controls caught by FindControl in
 * main.c before this runs; the shared gear is handled by ui_click before this. */
static int carousel_click(Ui *u, Point pt, UiCommand *out)
{
    CarLayout L;
    int       s;
    carousel_layout(u, &L);
    if (PtInRect(pt, &L.catBand)) {
        model_move_cat(u->m, pt.h < L.catMidX ? -1 : +1);
        return 1;
    }
    if (!L.hasItems) return 0;
    for (s = 0; s < L.nTiles; s++) {
        Rect col;
        int  idx = L.first + s;
        if (idx >= L.count) break;
        carousel_tile_box(&L, s, 0, &col);
        if (PtInRect(pt, &col)) {
            if (idx == u->m->curItem) { u->status[0] = '\0'; *out = UI_LAUNCH; }
            else model_move_item(u->m, idx - u->m->curItem);
            return 1;
        }
    }
    return 0;
}

static const BrowseView gCarouselView = { "Carousel",  draw_carousel, carousel_nav, carousel_idle, carousel_click, carousel_draw_sel, carousel_draw_art };
static const BrowseView gIconView     = { "Icon Grid", draw_iconview, iconview_nav, iconview_idle, iconview_click, iconview_draw_sel, iconview_draw_art };
static const BrowseView gListView     = { "List",      draw_listview, listview_nav, listview_idle, listview_click, listview_draw_sel, listview_draw_art };
static const BrowseView *const gViews[VIEW_N] = {
    &gCarouselView,   /* VIEW_CAROUSEL */
    &gIconView,       /* VIEW_ICON */
    &gListView,       /* VIEW_LIST */
};
static const BrowseView *cur_view(Ui *u)
{
    int v = u->view;
    if (v < 0 || v >= VIEW_N) v = VIEW_CAROUSEL;
    return gViews[v];
}

/* ---- real Control-Manager controls (docs/28) ----------------------------------
 * Per Apple's HIG + Inside Macintosh: real scroll bars (scrollBarProc) + push
 * buttons (pushButProc). They live in the window port and are (re)drawn AFTER the
 * off-screen GWorld is blitted (Decision A) — a fixed pair, created once and
 * repositioned per view (Decision C). All three browse views show them: the grid +
 * list as a vertical scroll bar at the edge, the carousel as a horizontal ◀▶ pager
 * along its band bottom; the same Launch button moves to each view's layout. */
static void ensure_controls(Ui *u)
{
    Rect z;
    if (u->controlsReady || !u->win) return;
    SetRect(&z, 0, 0, SBW, 100);
    u->scrollV   = NewControl(u->win, &z, "\p", false, 0, 0, 0, scrollBarProc, 0L);
    u->scrollCat = NewControl(u->win, &z, "\p", false, 0, 0, 0, scrollBarProc, 0L);  /* List categories */
    SetRect(&z, 0, 0, 84, 20);
    u->launch    = NewControl(u->win, &z, "\pLaunch", false, 1, 0, 1, pushButProc, 0L);
    u->quitBtn   = NewControl(u->win, &z, "\pQuit",   false, 1, 0, 1, pushButProc, 0L);
    u->cancelBtn = NewControl(u->win, &z, "\pCancel", false, 1, 0, 1, pushButProc, 0L);
    /* Header-left settings button: a standard push button (empty title — we draw a
     * gear glyph over it in ui_paint_controls) that opens the Quick-Launch menu. */
    SetRect(&z, 0, 0, 26, 20);
    u->settingsBtn = NewControl(u->win, &z, "\p", false, 1, 0, 1, pushButProc, 0L);
    u->controlsReady = (u->scrollV && u->scrollCat && u->launch && u->quitBtn && u->cancelBtn &&
                        u->settingsBtn) ? 1 : 0;
}

/* The quit-confirm dialog's panel + its two button rects (shared by draw + the
 * control placement). */
#define QC_PW 344
#define QC_PH 116
static void quitconfirm_rects(Ui *u, Rect *panel, Rect *quitBtn, Rect *cancelBtn)
{
    int   W = win_w(u), H = win_h(u);
    short px = (short)((W - QC_PW) / 2), py = (short)((H - QC_PH) / 2);
    SetRect(panel, px, py, (short)(px + QC_PW), (short)(py + QC_PH));
    SetRect(quitBtn,   (short)(px + QC_PW - 90),  (short)(py + QC_PH - 34),
            (short)(px + QC_PW - 20),  (short)(py + QC_PH - 14));
    SetRect(cancelBtn, (short)(px + QC_PW - 184), (short)(py + QC_PH - 34),
            (short)(px + QC_PW - 110), (short)(py + QC_PH - 14));
}

/* Header-left settings button geometry — a fixed rect (no font metrics) shared by the
 * control placement and the focus ring. */
static void settings_btn_rect(Rect *r) { SetRect(r, 5, 5, 31, 25); }

/* A little cog glyph, drawn straight into the window over the (empty) settings push
 * button after its CDEF paints — QuickDraw, since ui_paint_controls runs after the
 * off-screen blit and owns the window port. Eight rim teeth, a filled hub, a white
 * centre. Black-on-white reads on the button's standard white face in either theme. */
static void draw_gear_glyph(short cx, short cy)
{
    static const signed char dx[8] = {  0,  4,  6,  4,  0, -4, -6, -4 };
    static const signed char dy[8] = { -6, -4,  0,  4,  6,  4,  0, -4 };
    Rect o;
    int  i;
    ForeColor(blackColor);
    BackColor(whiteColor);                                     /* hub hole erases to white */
    for (i = 0; i < 8; i++) {                                  /* rim teeth */
        SetRect(&o, (short)(cx + dx[i] - 1), (short)(cy + dy[i] - 1),
                (short)(cx + dx[i] + 2), (short)(cy + dy[i] + 2));
        PaintRect(&o);
    }
    SetRect(&o, (short)(cx - 5), (short)(cy - 5), (short)(cx + 5), (short)(cy + 5));
    PaintOval(&o);                                             /* cog body */
    SetRect(&o, (short)(cx - 2), (short)(cy - 2), (short)(cx + 2), (short)(cy + 2));
    EraseOval(&o);                                             /* hub hole */
}

/* Reposition a control only when its rect actually changed, so a per-frame repaint
 * doesn't erase+redraw (flicker) a control that hasn't moved. */
static void place_control(ControlHandle c, const Rect *want)
{
    Rect cur = (**c).contrlRect;
    if (cur.left != want->left || cur.top != want->top)
        MoveControl(c, want->left, want->top);
    if ((cur.right - cur.left) != (want->right - want->left) ||
        (cur.bottom - cur.top) != (want->bottom - want->top))
        SizeControl(c, (short)(want->right - want->left), (short)(want->bottom - want->top));
}

/* Position + value + show + repaint the controls over the freshly-blitted content.
 * Hidden (so FindControl ignores them) outside the grid/list browse screens. */
/* `incremental` = repainting after an in-page selection move (browse_redraw), where
 * the blit deliberately straddles the real controls: the header steppers, the scroll
 * bar, and the Launch button are all left untouched by the copy, so we only nudge the
 * scroll thumb (SetControlValue) and never re-show/redraw the rest — re-drawing them
 * is what made the steppers and Launch flash on every item move. A full paint
 * (incremental = 0) lays out and draws everything. */
static void ui_paint_controls(Ui *u, int incremental)
{
    Rect sb, lb;
    int  n, vis, val, max, canLaunch, vtop = 0;
    ensure_controls(u);
    if (!u->controlsReady) return;
    if (u->mode == UI_MODE_QUITCONFIRM) {       /* the modal's two real buttons */
        Rect panel, qb, cb, ring;
        quitconfirm_rects(u, &panel, &qb, &cb);
        HideControl(u->scrollV); HideControl(u->scrollCat); HideControl(u->launch); HideControl(u->settingsBtn);
        place_control(u->quitBtn, &qb);   ShowControl(u->quitBtn);   Draw1Control(u->quitBtn);
        place_control(u->cancelBtn, &cb);  ShowControl(u->cancelBtn); Draw1Control(u->cancelBtn);
        /* the bold default-button ring around Quit (the CDEF doesn't draw it) */
        ring = qb; InsetRect(&ring, -4, -4);
        PenSize(3, 3); ForeColor(blackColor);
        FrameRoundRect(&ring, 16, 16);
        PenSize(1, 1);
        return;
    }
    HideControl(u->quitBtn);
    HideControl(u->cancelBtn);

    /* Header-left Settings button (a standard push button with a gear glyph, opens the
     * Quick-Launch menu) — all three browse views. Placed on a FULL paint only: the
     * header isn't re-blitted on an incremental move, so the button + gear stay put
     * (repositioning/redrawing per move is what flashed the old category steppers). A
     * focus ring shows when the keyboard has parked on it (Left at the first category). */
    if (!incremental) {
        if (!u->safe && u->mode == UI_MODE_LIST &&
            (u->view == VIEW_CAROUSEL || u->view == VIEW_ICON || u->view == VIEW_LIST)) {
            Rect sbr;
            settings_btn_rect(&sbr);
            place_control(u->settingsBtn, &sbr);
            ShowControl(u->settingsBtn);
            Draw1Control(u->settingsBtn);
            draw_gear_glyph((short)((sbr.left + sbr.right) / 2), (short)((sbr.top + sbr.bottom) / 2));
            if (u->settingsFocus) {                            /* keyboard focus ring */
                Rect ring = sbr; InsetRect(&ring, -3, -3);
                PenSize(2, 2); ForeColor(blackColor);
                FrameRoundRect(&ring, 8, 8);
                PenSize(1, 1);
            }
        } else {
            HideControl(u->settingsBtn);
        }
    }

    if (u->safe || u->mode != UI_MODE_LIST ||
        (u->view != VIEW_CAROUSEL && u->view != VIEW_ICON && u->view != VIEW_LIST)) {
        HideControl(u->scrollV);
        HideControl(u->scrollCat);
        HideControl(u->launch);
        return;
    }
    if (u->view == VIEW_CAROUSEL) {
        CarLayout L; carousel_layout(u, &L);
        sb = L.pager;          /* horizontal scroll bar along the band bottom */
        lb = L.launchBtn;      /* Launch button below the strip                */
        n = L.count; vis = L.nTiles;          /* tiles visible at once         */
    } else if (u->view == VIEW_ICON) {
        GridLayout g; grid_layout(u, &g);
        SetRect(&sb, g.gridRight, (short)HEADER_H, (short)(g.gridRight + SBW), (short)(win_h(u) - HINT_H));
        n = g.n; vis = g.vis * g.cols;
        grid_launch_rect(&g, &lb);              /* same rect the incremental blit avoids */
    } else {  /* VIEW_LIST */
        ListLayout L; list_layout(u, &L);
        SetRect(&sb, (short)(win_w(u) - SBW), (short)(L.bTop + 24), (short)win_w(u), L.lstBot);
        n = L.nItems; vis = L.itemRows; vtop = L.itemTop;
        list_launch_rect(u, &L, &lb);           /* same rect the incremental blit avoids */
    }
    /* The List bar scrolls the VIEW (value = the top visible row, range = the off-screen
     * rows); the carousel/grid bars still track the selection. Inactive (max == min) when
     * everything fits, per HIG. */
    if (u->view == VIEW_LIST) { max = (n > vis) ? (n - vis) : 0; val = (n > vis) ? vtop : 0; }
    else                      { max = (n > vis) ? (n - 1)   : 0; val = (n > vis) ? u->m->curItem : 0; }
    place_control(u->scrollV, &sb);
    SetControlMaximum(u->scrollV, (short)max);
    SetControlValue(u->scrollV, (short)val);           /* moves just the thumb */
    if (!incremental) { ShowControl(u->scrollV); Draw1Control(u->scrollV); }
    /* On an incremental pass the blit never touches the scroll-bar gutter, so the bar
     * itself is intact — SetControlValue already re-drew the thumb; no full redraw. */

    /* Categories-pane scroll bar (List view only): shown when the categories overflow. */
    if (u->view == VIEW_LIST) {
        ListLayout L; list_layout(u, &L);
        if (u->m->ncats > L.catRows) {
            Rect cb; SetRect(&cb, L.catW, (short)(L.bTop + 24), (short)LPANE, L.bBot);
            place_control(u->scrollCat, &cb);
            SetControlMaximum(u->scrollCat, (short)(u->m->ncats - L.catRows));
            SetControlValue(u->scrollCat, (short)L.catTop);
            if (!incremental) { ShowControl(u->scrollCat); Draw1Control(u->scrollCat); }
        } else {
            HideControl(u->scrollCat);
        }
    } else {
        HideControl(u->scrollCat);
    }

    canLaunch = (model_cur_item(u->m) != 0);
    place_control(u->launch, &lb);
    HiliteControl(u->launch, (short)(canLaunch ? 0 : 255));
    if (!incremental) {
        ShowControl(u->launch);
        Draw1Control(u->launch);
    } else if (!u->r->useOffscreen && (u->view == VIEW_ICON || u->view == VIEW_LIST)) {
        /* Direct-draw path only: the grid/list detail fill drew straight onto the
         * window and painted over the Launch button, so put it back. (Off-screen, the
         * blit is split around the button; the carousel never draws over it — so in
         * both of those cases the button is left untouched, no flicker.) */
        Draw1Control(u->launch);
    }
}

/* The quit-confirmation modal: a centred panel + message. The Quit (default) and
 * Cancel buttons are real push-button controls drawn by ui_paint_controls. */
static void draw_quitconfirm(Ui *u)
{
    Render     *r = u->r;
    Rect        panel, qb, cb;
    const char *msg = "Are you sure you want to quit MacAtrium?";
    short       cw, mid;
    quitconfirm_rects(u, &panel, &qb, &cb);
    u->panelRect = panel;                                    /* blit/erase region */
    render_fill(r, &panel, FILL_PANEL);
    render_frame(r, &panel);
    render_base_text(r);
    mid = (short)(panel.left + (panel.right - panel.left) / 2);
    cw = render_text_width(r, msg);
    render_text(r, (short)(mid - cw / 2), (short)(panel.top + 34), msg, INK_TITLE);
    { const char *t = "The Finder will come back.";
      cw = render_text_width(r, t);
      render_text(r, (short)(mid - cw / 2), (short)(panel.top + 54), t, INK_DIM); }
}

static int is_overlay_mode(int mode)
{
    return mode == UI_MODE_CTLPANELS || mode == UI_MODE_QUITCONFIRM;
}

/* The window rect an overlay panel occupies, by mode (centred) — mirrors the panel
 * geometry each draw_* computes, so ui_draw can decide the blit / erase region
 * before drawing. Returns 1 for an overlay mode, 0 otherwise. */
static int overlay_panel_rect(Ui *u, int mode, Rect *p)
{
    int   W = win_w(u), H = win_h(u), pw, ph;
    short px, py;
    switch (mode) {
        case UI_MODE_CTLPANELS:   pw = 320;   ph = 9 * (ROW_H + 2) + 56;        break;
        case UI_MODE_QUITCONFIRM: pw = QC_PW; ph = QC_PH;                       break;
        default: SetRect(p, 0, 0, 0, 0); return 0;
    }
    px = (short)((W - pw) / 2); py = (short)((H - ph) / 2);
    SetRect(p, px, py, (short)(px + pw), (short)(py + ph));
    return 1;
}

/* 1 if rect b lies fully inside rect a. */
static int rect_contains(const Rect *a, const Rect *b)
{
    return a->left <= b->left && a->top <= b->top &&
           a->right >= b->right && a->bottom >= b->bottom;
}

void ui_draw(Ui *u)
{
    int carouselRepainted = 0, setupPartial = 0;
    /* Keep the colour backend matched to the live screen depth on *every* repaint,
     * including ones that bypass ui_idle's poll — e.g. the updateEvt the system
     * posts when the screen depth changes (our startup 1-bit->8-bit bump). Without
     * this, that first repaint paints with the stale (B&W) backend and the screen
     * stays black until the user happens to press a key. Lightweight: only re-fits
     * when the depth actually differs; ui_idle still does the full re-fit (art and
     * icon caches are depth-specific). */
    {
        short now = display_current_depth();
        if (u->r->depth != now) render_reset_for_depth(u->r, u->env, now);
    }

    render_begin(u->r, u->win);
    /* On a mode change, repaint the browse view underneath only when the new screen
     * won't itself cover what the previous one drew. Opening an overlay from a clean
     * LIST keeps the carousel (the panel just composites on top, then we blit only
     * the panel). Leaving a full-screen card, closing an overlay, or switching to an
     * overlay whose panel doesn't fully cover the previous one all need the repaint
     * to erase the old pixels. */
    if (u->mode != u->lastMode) {
        if (u->lastMode == -1) {
            u->bgValid = 0;                /* very first paint */
        } else if (u->lastMode != UI_MODE_LIST) {
            if (is_overlay_mode(u->lastMode) && is_overlay_mode(u->mode)) {
                Rect np;                   /* overlay -> overlay: only if new won't cover old */
                overlay_panel_rect(u, u->mode, &np);
                if (!rect_contains(&np, &u->panelRect)) u->bgValid = 0;
            } else {
                u->bgValid = 0;            /* full-screen card, or overlay -> list (close) */
            }
        }
        u->overlayDrawn = 0;               /* a switched/opened overlay draws fully once */
        u->setupDrawn = 0;                 /* re-entering the chooser draws fully once */
        u->lastMode = u->mode;
    }
    if (u->mode == UI_MODE_SETUP) {
        setupPartial = draw_setup(u);   /* 1 = only the changed rows repainted */
        u->bgValid = 0;                 /* full-screen first-run chooser */
    } else if (u->mode == UI_MODE_PREVIEW) {
        draw_preview(u);
        u->bgValid = 0;                 /* full-screen view -> carousel not in GWorld */
    } else if (u->mode == UI_MODE_INFO) {
        draw_info(u);
        u->bgValid = 0;
    } else if (u->mode == UI_MODE_ABOUT) {
        draw_about(u);
        u->bgValid = 0;                 /* full-screen card -> carousel not in GWorld */
    } else {
        /* The menu / settings / control-panels panels are overlays. When only the
         * overlay's selection changed, the carousel behind it is already in the
         * GWorld, so skip repainting it — that's what made menu Up/Down lurch. */
        int overlay = is_overlay_mode(u->mode);
        if (!overlay || !u->bgValid) {
            if (u->safe) draw_safe(u);
            else {
                /* Full repaint: pre-load the detail cover (off-screen path) so a view
                 * switch / scroll / category change shows it in this same pass. An
                 * in-page grid/list move takes the incremental *_draw_sel path instead
                 * and defers the cover to idle (draw_detail_art stays a pure draw). */
                if (u->r->useOffscreen) ensure_art_loaded(u);
                cur_view(u)->draw(u);            /* current browse view (carousel/grid/list) */
            }
            u->bgValid = 1;
            u->overlayDrawn = 0;           /* the repaint erased any overlay panel */
            carouselRepainted = 1;
        }
        if (u->mode == UI_MODE_CTLPANELS)
            draw_ctlpanels(u);
        else if (u->mode == UI_MODE_QUITCONFIRM)
            draw_quitconfirm(u);
    }
    /* An overlay drawn over an unchanged browse view only dirtied its own panel —
     * copy just that region, not the whole window (the flash). Full-screen modes and
     * any browse repaint copy the window. (No-op on the direct-draw B&W path.) */
    if (setupPartial || (is_overlay_mode(u->mode) && !carouselRepainted))
        render_end_rect(u->r, u->win, &u->panelRect);
    else
        render_end(u->r, u->win);
    ui_paint_controls(u, 0);       /* full: real scroll bar + Launch + category steppers */
}

/* Re-blit the browse screen from the off-screen buffer without re-rendering it — used
 * when a real modal window (Quick-Launch menu / Settings) closes and the buffer still
 * holds the clean browse (the window never touched it). Far cheaper than ui_draw and
 * avoids the full-screen repaint flash. Falls back to a full draw on the direct-draw
 * path (no buffer to blit) or when a setting in the dialog invalidated the buffer. */
void ui_reblit(Ui *u)
{
    if (!u->r->useOffscreen || !u->bgValid || u->mode != UI_MODE_LIST) { ui_draw(u); return; }
    render_begin(u->r, u->win);        /* no drawing between begin/end == just re-blit */
    render_end(u->r, u->win);
    ui_paint_controls(u, 0);
}

int ui_idle(Ui *u)
{
    /* Pick up a screen-depth change made *outside* MacAtrium — the Monitors
     * control panel, or the emulator's own video setting — so colour engages
     * (or B&W falls back) without a trip through our Settings. Our own Settings
     * path goes through apply_depth(); this covers everything else. On a machine
     * with no Color QD (or only 1-bit available) display_current_depth() stays
     * at 1, so this is a no-op. Checked every idle tick (GetMainDevice is cheap). */
    {
        short now = display_current_depth();
        if (now != u->env->pixelSize) {
            u->env->pixelSize = now;
            u->env->useColor  = (u->env->hasColorQD && now >= 4);
            render_reset_for_depth(u->r, u->env, now);
            if (u->listArt) { art_dispose(u->listArt); u->listArt = 0; }
            u->artFor = 0;                       /* art variant is depth-specific  */
            dispose_row_icons(u);                /* icl8/ICN# variant too          */
            u->bgValid = 0;                      /* whole screen must repaint      */
            return UI_IDLE_FULL;
        }
    }

    if (u->safe || u->mode != UI_MODE_LIST) return UI_IDLE_NONE;  /* only the browse view loads art */
    /* Deferred cover load (direct-draw path): repaint ONLY the cover box, not the
     * whole screen — that second full repaint was the "double refresh" on flip. */
    return cur_view(u)->idle(u);
}

/* Repaint only the detail cover/screenshot box (the deferred-load target) — the
 * current view's targeted art repaint. On the off-screen path the cover is loaded
 * synchronously in the view's draw, so this is the direct-path / settle refresh. */
void ui_draw_art(Ui *u)
{
    if (u->safe || u->mode != UI_MODE_LIST) return;
    /* Repaints only the cover box, which never overlaps a real control — so, unlike a
     * selection move, there's nothing to put back afterward (no ui_paint_controls). */
    if (cur_view(u)->draw_art) cur_view(u)->draw_art(u);
}

/* Repaint just the items pane (its rows region), optionally the detail strip, into the
 * off-screen buffer and blit ONLY those rects — a view scroll (or a selection move that
 * scrolled) without re-blitting the whole window. Falls back to a full ui_draw when
 * off-screen compositing isn't available. */
static void list_repaint_items(Ui *u, int withDetail)
{
    ListLayout L;
    Render    *r = u->r;
    int        i, W = win_w(u), nr = 0;
    Rect       region, rects[8];
    if (!r->useOffscreen || !u->bgValid || u->mode != UI_MODE_LIST) { ui_draw(u); return; }
    list_layout(u, &L);
    render_begin(r, u->win);
    SetRect(&region, L.rx, (short)(L.bTop + 24), (short)(W - SBW), L.lstBot);
    render_fill(r, &region, FILL_BG);
    for (i = 0; i < L.itemRows && L.itemTop + i < L.nItems; i++)
        draw_list_item_row(u, &L, i);
    if (!u->filter[0]) {                                   /* the Name|Type divider */
        short nameX, typeX, yearX;
        list_col_x(u, &nameX, &typeX, &yearX);
        vbar(u, (short)(typeX - 6), (short)(L.bTop + 24), (short)(L.lstBot - (L.bTop + 24)));
    }
    rects[nr++] = region;
    if (withDetail) {                                      /* selection changed -> detail too */
        Rect strip, lb;
        draw_list_detail(u, &L);
        SetRect(&strip, L.rx, L.lstBot, (short)W, L.bBot);
        list_launch_rect(u, &L, &lb);
        push_around(rects, &nr, 8, &strip, &lb);           /* keep the Launch button intact */
    }
    render_end_rects(r, u->win, rects, nr);
    u->lastDrawnTop  = L.itemTop;
    u->lastDrawnItem = u->m->curItem;
    ui_paint_controls(u, 1);
}

/* Repaint just the categories pane (its rows region) + blit it. */
static void list_repaint_cats(Ui *u)
{
    ListLayout L;
    Render    *r = u->r;
    int        i;
    Rect       region;
    if (!r->useOffscreen || !u->bgValid || u->mode != UI_MODE_LIST) { ui_draw(u); return; }
    list_layout(u, &L);
    render_begin(r, u->win);
    SetRect(&region, 0, (short)(L.bTop + 24), L.catW, L.bBot);
    render_fill(r, &region, FILL_BG);
    for (i = 0; i < L.catRows && L.catTop + i < u->m->ncats; i++)
        draw_list_cat_row(u, &L, i);
    render_end_rects(r, u->win, &region, 1);
    u->lastDrawnCatTop = L.catTop;
    ui_paint_controls(u, 1);
}

/* Minimal List-view repaint after a selection/scroll change: a category or focus change
 * needs the full window; a pane scroll repaints just that pane; an in-page selection move
 * repaints the two changed rows. Returns 0 to fall back to a full ui_draw. */
static int list_try_incremental(Ui *u)
{
    ListLayout L;
    if (!u->bgValid) return 0;
    list_layout(u, &L);
    if (u->m->curCat != u->lastDrawnCat || u->listFocus != u->lastDrawnFocus) return 0;
    if (L.itemTop != u->lastDrawnTop) {                    /* items pane scrolled */
        list_repaint_items(u, u->m->curItem != u->lastDrawnItem);
        return 1;
    }
    if (L.catTop != u->lastDrawnCatTop) {                  /* categories pane scrolled */
        list_repaint_cats(u);
        return 1;
    }
    if (u->m->curItem != u->lastDrawnItem)                 /* in-page selection move */
        return listview_draw_sel(u) ? (ui_paint_controls(u, 1), 1) : 0;
    return 1;                                              /* nothing visible changed */
}

/* Repaint after a browse-view selection/scroll change: an incremental redraw of just the
 * changed cells/detail/pane when the view is already on-screen, else a full ui_draw (a
 * category change, an overlay, a non-list mode). This is the Mac update model — redraw
 * only what changed instead of the whole window. */
static void browse_redraw(Ui *u)
{
    if (u->mode == UI_MODE_LIST && !u->safe && u->bgValid && u->view == VIEW_LIST) {
        if (list_try_incremental(u)) return;
    } else if (u->mode == UI_MODE_LIST && !u->safe && u->bgValid &&
               cur_view(u)->draw_sel && cur_view(u)->draw_sel(u)) {
        ui_paint_controls(u, 1);   /* carousel / grid: just the scroll thumb, no full redraw */
        return;
    }
    ui_draw(u);
}

/* Scroll the List items/categories view by `delta` rows (clamped), then repaint. The
 * selection is left where it is — a real Mac list scroll bar moves the view, not the
 * selection. */
static void list_scroll_items(Ui *u, int delta)
{
    ListLayout L; int max, top;
    list_layout(u, &L);
    max = L.nItems - L.itemRows; if (max < 0) max = 0;
    top = u->listItemTop + delta; if (top > max) top = max; if (top < 0) top = 0;
    if (top == u->listItemTop) return;
    u->listItemTop = top;
    browse_redraw(u);
}
static void list_scroll_cats(Ui *u, int delta)
{
    ListLayout L; int max, top;
    list_layout(u, &L);
    max = u->m->ncats - L.catRows; if (max < 0) max = 0;
    top = u->listCatTop + delta; if (top > max) top = max; if (top < 0) top = 0;
    if (top == u->listCatTop) return;
    u->listCatTop = top;
    browse_redraw(u);
}

/* Step the items scroll bar by an arrow/page part (called by main.c after TrackControl).
 * List view: scroll the VIEW (selection stays put). Carousel/grid: step the selection. */
void ui_scroll_step(Ui *u, short part)
{
    if (u->view == VIEW_LIST) {
        ListLayout L; int step = 0; list_layout(u, &L);
        switch (part) {
            case inUpButton:   step = -1;          break;
            case inDownButton: step = +1;          break;
            case inPageUp:     step = -L.itemRows; break;
            case inPageDown:   step = +L.itemRows; break;
            default: return;
        }
        list_scroll_items(u, step);
        return;
    }
    {   ModelCat *cat = model_cur_cat(u->m);
        int n = cat ? cat->count : 0, page = 1, step = 0, target;
        if (n <= 0) return;
        if (u->view == VIEW_ICON) { GridLayout g; grid_layout(u, &g); page = g.vis * g.cols; }
        else                      { CarLayout L; carousel_layout(u, &L); page = L.nTiles; }
        if (page < 1) page = 1;
        switch (part) {
            case inUpButton:   step = -1;    break;
            case inDownButton: step = +1;    break;
            case inPageUp:     step = -page; break;
            case inPageDown:   step = +page; break;
            default: return;
        }
        target = u->m->curItem + step;
        if (target < 0) target = 0;
        if (target >= n) target = n - 1;
        if (target != u->m->curItem) { model_move_item(u->m, target - u->m->curItem); browse_redraw(u); }
    }
}

/* Jump to the thumb's value after a drag. List = view offset; carousel/grid = selection. */
void ui_scroll_to(Ui *u, short val)
{
    if (u->view == VIEW_LIST) {
        ListLayout L; int max, top; list_layout(u, &L);
        max = L.nItems - L.itemRows; if (max < 0) max = 0;
        top = val; if (top > max) top = max; if (top < 0) top = 0;
        if (top != u->listItemTop) { u->listItemTop = top; browse_redraw(u); }
        return;
    }
    {   ModelCat *cat = model_cur_cat(u->m);
        int n = cat ? cat->count : 0, target = val;
        if (n <= 0) return;
        if (target < 0) target = 0;
        if (target >= n) target = n - 1;
        if (target != u->m->curItem) { model_move_item(u->m, target - u->m->curItem); browse_redraw(u); }
    }
}

/* The categories-pane scroll bar (List view only): scroll the category VIEW. */
void ui_scroll_cat_step(Ui *u, short part)
{
    ListLayout L; int step = 0;
    if (u->view != VIEW_LIST) return;
    list_layout(u, &L);
    switch (part) {
        case inUpButton:   step = -1;         break;
        case inDownButton: step = +1;         break;
        case inPageUp:     step = -L.catRows; break;
        case inPageDown:   step = +L.catRows; break;
        default: return;
    }
    list_scroll_cats(u, step);
}
void ui_scroll_cat_to(Ui *u, short val)
{
    if (u->view != VIEW_LIST) return;
    list_scroll_cats(u, val - u->listCatTop);
}

/* ---- Quick-Launch menu model (the real menu window in main.c renders these) ---- */
int ui_menu_count(Ui *u) { return u->nmenu; }

const char *ui_menu_label(Ui *u, int i)
{
    if (i < 0 || i >= u->nmenu) return "";
    return kMenuLabel[u->menuRows[i]];
}

UiCommand ui_menu_command(Ui *u, int i)
{
    if (i < 0 || i >= u->nmenu) return UI_NONE;
    switch (u->menuRows[i]) {
        case MROW_SETTINGS:    return UI_OPEN_SETTINGS;
        case MROW_SHOW_FINDER: return UI_SHOW_FINDER;
        case MROW_EXIT:        return UI_QUIT;
        case MROW_RESTART:     return UI_RESTART;
        case MROW_SHUTDOWN:    return UI_SHUTDOWN;
        case MROW_CHOOSE_OS:   return UI_OPEN_CHOOSER;
        case MROW_STATUS:      return UI_SHOW_STATUS;
        case MROW_CDLIST:      return UI_OPEN_CDLIST;
    }
    return UI_NONE;
}

/* ---- input ---------------------------------------------------------------- */

/* Build "<base>.<depth>.<ext>" into buf (depth is 1/4/8/16). */
static void art_variant_path(char *buf, const char *base, int depth, const char *ext)
{
    int n;
    strcpy(buf, base);
    n = (int)strlen(buf);
    buf[n++] = '.';
    if (depth >= 10) { buf[n++] = (char)('0' + depth / 10); buf[n++] = (char)('0' + depth % 10); }
    else             { buf[n++] = (char)('0' + depth); }
    buf[n++] = '.';
    strcpy(buf + n, ext);
}

/* The vRefNum of the current category's source volume (multi-disk, docs/37); the
 * boot volume when there's no volume table (legacy / safe screen). All art on the
 * resident page shares this volume — a page is one disk's one sub-page. */
static short ui_cur_vref(Ui *u)
{
    short bv;
    if (u->vols && u->vols->n > 0) {
        int vol = 0;
        if (u->m && u->m->curCat >= 0 && u->m->curCat < u->m->ncats)
            vol = u->m->cats[u->m->curCat].vol;
        if (vol < 0 || vol >= u->vols->n) vol = 0;
        return u->vols->v[vol].vref;
    }
    if (macfs_boot_vref(&bv) == noErr) return bv;
    return 0;
}

/* Load the depth variant for `base`. 1-bit art ships as a raw CopyBits bitmap
 * (.raw) — preferred over a .pict because DrawPicture faults Snow on some valid
 * 1-bit art (docs/14); fall back to a .pict variant if the .raw is absent. */
static Art *load_variant(short vref, const char *base, int depth)
{
    char buf[208];
    Art *p;
    if (depth == 1) {
        art_variant_path(buf, base, 1, "raw");
        p = art_load(vref, buf);
        if (p) return p;
    }
    art_variant_path(buf, base, depth, "pict");
    return art_load(vref, buf);
}

/* Resolve an item's `image` to an Art. An explicit ".pict"/".raw" path loads
 * directly; otherwise it's a base path and we pick the depth variant matching
 * the screen (e.g. "images/foo" -> "images/foo.1.raw" on a 1-bit screen),
 * falling back to shallower depths then "<base>.pict"/".raw". This keeps a
 * 1-bit screen from ever drawing a colour PICT (docs/06 depth variants). */
static Art *load_item_art(Ui *u, const char *image)
{
    int n = (int)strlen(image);
    char buf[208];
    Art *p;
    int cand[5], nc = 0, i, depth;
    short vref = ui_cur_vref(u);   /* art loads from the item's source disk (docs/37) */
    /* Art-tier ceiling -- deliberately wide open (24). docs/44 P2 (the budget-aware
     * loader) is NOT finished: the ArtCaps affordability estimate (artcaps.c
     * peak_art_bytes, a coarse uncompressed 720^2 guess) under-budgets 8-bit on a real
     * Quadra granted the 1 MB SIZE minimum and wrongly collapses maxAffordableDepth to
     * 1, so covers load the 1-bit ABMP (B&W) even though the 8-bit PICT is present,
     * displayable and actually fits. Do NOT gate art on that startup estimate: the
     * authoritative memory guard is the per-resource on-disk size check in
     * art_load_rsrc (live MaxBlock, art.c:151-173), which drops a tier only when it
     * truly won't fit -- no OOM. (ArtCaps is still probed and shown in Status; it just
     * doesn't veto art loading until P2 lands.) */
    short cap = 24;

    if (n >= 5 && strcmp(image + n - 5, ".rsrc") == 0)
        return art_load_rsrc(vref, image, (short)u->env->pixelSize, cap);
    if ((n >= 5 && strcmp(image + n - 5, ".pict") == 0) ||
        (n >= 4 && strcmp(image + n - 4, ".raw") == 0))
        return art_load(vref, image);

    /* Pick the best available variant for the screen depth: the native depth
     * first, then *higher* depths (QuickDraw down-converts a deeper PICT to the
     * screen — docs/15, verified), then *lower* colour depths, and the 1-bit raw
     * last. So a single deep master (e.g. `<id>.24.pict`) covers every colour
     * screen, while a 1-bit screen still prefers the ordered-dither `<id>.1.raw`.
     * (Encoder depths: 1/4/8 indexed, 16/24 direct.) */
    depth = u->env->pixelSize;
    if (depth > cap) depth = cap;                 /* effective art depth = min(screen, ceiling) */
    if      (depth <= 1)  { cand[nc++]=1;  cand[nc++]=8;  cand[nc++]=16; cand[nc++]=24; cand[nc++]=4; }
    else if (depth <= 4)  { cand[nc++]=4;  cand[nc++]=8;  cand[nc++]=16; cand[nc++]=24; cand[nc++]=1; }
    else if (depth <= 8)  { cand[nc++]=8;  cand[nc++]=16; cand[nc++]=24; cand[nc++]=4;  cand[nc++]=1; }
    else if (depth <= 16) { cand[nc++]=16; cand[nc++]=24; cand[nc++]=8;  cand[nc++]=4;  cand[nc++]=1; }
    else                  { cand[nc++]=24; cand[nc++]=16; cand[nc++]=8;  cand[nc++]=4;  cand[nc++]=1; }
    /* drop any variant deeper than the affordability ceiling (keeps exact→deeper→
     * shallower *within* it), so we never even try a cover the budget can't hold. */
    { int j = 0; for (i = 0; i < nc; i++) if (cand[i] <= cap) cand[j++] = cand[i]; nc = j; }

    for (i = 0; i < nc; i++) {
        p = load_variant(vref, image, cand[i]);
        if (p) return p;
    }
    strcpy(buf, image);
    strcat(buf, ".pict");
    p = art_load(vref, buf);
    if (p) return p;
    strcpy(buf, image);
    strcat(buf, ".raw");
    p = art_load(vref, buf);
    if (p) return p;
    /* last resort: the app's own Finder icon, baked as a raw bitmap (docs/14). */
    strcpy(buf, image);
    strcat(buf, ".icon.raw");
    return art_load(vref, buf);
}

/* Switch the screen to `depth` bits and re-fit our rendering to it. Called ONLY from
 * the Settings "Color Depth" stepper — the sole place we persist a boot default. */
static void apply_depth(Ui *u, short depth)
{
    if (display_set_depth(depth) != noErr) return;
    u->env->pixelSize = display_current_depth();   /* re-read what we actually got */
    /* THE ONE slot-PRAM write in the whole app: an explicit user depth choice becomes
     * the system's boot default (display_set_default_depth only commits it because the
     * screen is now live at this depth). Nowhere else touches slot PRAM. main also saves
     * the depth to prefs so the launcher re-applies it live on the next boot. */
    (void)display_set_default_depth(u->env->pixelSize);
    u->env->useColor  = (u->env->hasColorQD && u->env->pixelSize >= 4);
    render_reset_for_depth(u->r, u->env, u->env->pixelSize);
    if (u->listArt) {                              /* art variant is depth-specific */
        art_dispose(u->listArt); u->listArt = 0; u->artFor = 0;
    }
    dispose_row_icons(u);                          /* icl8/ICN# variant is depth-specific */
    u->bgValid = 0;                                /* whole screen must repaint */
}

/* Change the selected Settings row's value by `dir` (-1 / +1). Returns 1 if a
 * *persisted* preference (theme / volume / colour depth) changed, so main can
 * save prefs. Colour depth now persists via slot PRAM (apply_depth →
 * display_set_default_depth) plus the prefs `depth` key (docs/15). */
static int settings_adjust_row(Ui *u, int row, int dir)
{
    switch (row) {
        case 0:                                    /* Theme (persisted) */
            render_toggle_theme(u->r);
            u->bgValid = 0;                         /* carousel colours changed */
            return 1;
        case 1: {                                  /* Color Depth (persisted) */
            int i, cur = 0;
            for (i = 0; i < u->ndepths; i++)
                if (u->depths[i] == u->env->pixelSize) cur = i;
            cur += dir;
            if (cur < 0) cur = 0;
            if (cur >= u->ndepths) cur = u->ndepths - 1;
            if (u->ndepths > 0 && u->depths[cur] != u->env->pixelSize) {
                apply_depth(u, u->depths[cur]);
                return 1;                           /* persist the new boot depth */
            }
            return 0;
        }
        case 2:                                    /* Volume (persisted) */
            if (u->vol >= 0) {
                int old = u->vol;
                u->vol += dir;
                if (u->vol < 0) u->vol = 0;
                if (u->vol > SOUND_VOL_MAX) u->vol = SOUND_VOL_MAX;
                sound_set_vol(u->vol);
                return (u->vol != old);
            }
            return 0;
        case 3:                                    /* Artwork: Box Art / Screenshot */
            u->artPref = u->artPref ? 0 : 1;
            if (u->listArt) { art_dispose(u->listArt); u->listArt = 0; }
            u->artFor = 0;                          /* force the detail pane to reload */
            u->bgValid = 0;                         /* carousel art changes */
            return 1;                               /* persisted */
        case 4:                                    /* Startup Sound On/Off (persisted) */
            u->sndStartup = u->sndStartup ? 0 : 1;
            if (u->sndStartup) sound_play_file("sounds/startup", 1);   /* preview */
            return 1;
        case 5:                                    /* Shutdown Sound On/Off (persisted) */
            u->sndShutdown = u->sndShutdown ? 0 : 1;
            if (u->sndShutdown) sound_play_file("sounds/shutdown", 1); /* preview */
            return 1;
        case 6:                                    /* View: Carousel / Icon Grid / List (persisted) */
            ui_filter_clear(u);                     /* the filter is List-view only */
            u->view = (u->view + dir + VIEW_N) % VIEW_N;
            u->bgValid = 0;                         /* the whole browse screen changes */
            return 1;
        case 7:                                    /* Categories list Show/Hide (persisted) */
            u->catList = u->catList ? 0 : 1;
            u->bgValid = 0;                         /* browse layout changes */
            return 1;
        case 8: {                                  /* Carousel icon count: odd 3..25 (persisted) */
            int n = u->carousel + dir * 2;
            if (n < 3)  n = 3;
            if (n > 25) n = 25;
            if (n == u->carousel) return 0;
            u->carousel = n;
            u->bgValid = 0;                         /* carousel layout changes */
            return 1;
        }
        case SET_ROW_MENUBAR:                      /* System menu bar Shown/Hidden */
            u->hideMenuBar = u->hideMenuBar ? 0 : 1;
            u->chromeDirty = 1;                     /* main re-lays out the window + bar */
            return 1;
        case SET_ROW_TITLEBAR:                     /* window title bar Shown/Hidden */
            u->hideTitleBar = u->hideTitleBar ? 0 : 1;
            u->chromeDirty = 1;
            return 1;
        case SET_ROW_TEXTSIZE: {                   /* content text size Small/Medium/Large */
            int sizes[3] = { TEXT_SMALL, TEXT_MEDIUM, TEXT_LARGE };
            int cur = 1, i;
            for (i = 0; i < 3; i++) if (sizes[i] == u->r->textSize) cur = i;
            cur = (cur + dir + 3) % 3;
            ui_set_text_size(u, sizes[cur]);        /* reflows everything (sets bgValid=0) */
            return 1;                               /* persisted */
        }
        case SET_ROW_GRIDSTYLE:                    /* Icon Grid: Finder / Tiles */
            u->gridStyle = (u->gridStyle + dir + GRID_N) % GRID_N;
            u->bgValid = 0;                         /* the grid relays out */
            return 1;                               /* persisted */
        case SET_ROW_APPEARANCE: {                 /* era look: Auto / Sys6 / Sys7 / Platinum */
            int pref = u->r->appearancePref;
            int idx  = (pref == APPEAR_AUTO) ? 0 : pref + 1;  /* 0=Auto,1=sys6,2=sys7,3=sys8 */
            idx  = (idx + dir + 4) % 4;
            pref = (idx == 0) ? APPEAR_AUTO : idx - 1;
            render_set_appearance(u->r, pref, u->env);
            u->bgValid = 0;                         /* re-render the themed chrome */
            return 1;                               /* persisted */
        }
        case SET_ROW_CDINSERT:                     /* CD auto-insert On/Off (persisted) */
            u->cdEnable = u->cdEnable ? 0 : 1;
            return 1;
        case SET_ROW_CDTIMEOUT: {                  /* CD mount wait: 5..60 s, step 5 */
            int n = u->cdTimeout + dir * 5;
            if (n < 5)  n = 5;
            if (n > 60) n = 60;
            if (n == u->cdTimeout) return 0;
            u->cdTimeout = n;
            return 1;
        }
        default:                                   /* Control Panels (action row, intercepted) */
            return 0;
    }
}

/* ---- Settings model exposed to the real Settings window (main.c) -------------- */
int ui_setting_count(void) { return SET_N; }

int ui_setting_kind(int row)
{
    switch (row) {
        case 0: case 3: case 4: case 5: case 7:
        case SET_ROW_MENUBAR: case SET_ROW_TITLEBAR: case SET_ROW_CDINSERT:
            return SETTING_CHECK;
        case SET_ROW_CTLPANELS:
            return SETTING_ACTION;
        default:                                   /* depth/vol/view/carousel/text/grid */
            return SETTING_STEPPER;
    }
}

const char *ui_setting_label(int row)
{
    switch (row) {
        case 0:                 return "Dark theme";
        case 1:                 return "Color Depth";
        case 2:                 return "Volume";
        case 3:                 return "Use screenshots";
        case 4:                 return "Startup sound";
        case 5:                 return "Shutdown sound";
        case 6:                 return "Browse View";
        case 7:                 return "Show categories list";
        case 8:                 return "Carousel icons";
        case SET_ROW_MENUBAR:   return "Hide menu bar";
        case SET_ROW_TITLEBAR:  return "Hide title bar";
        case SET_ROW_TEXTSIZE:  return "Text Size";
        case SET_ROW_GRIDSTYLE: return "Grid Style";
        case SET_ROW_APPEARANCE: return "Appearance";
        case SET_ROW_CDINSERT:  return "Auto-insert CDs";
        case SET_ROW_CDTIMEOUT: return "CD mount wait";
        default:                return "Control Panels\xC9";   /* 0xC9 = … */
    }
}

int ui_setting_checked(Ui *u, int row)
{
    switch (row) {
        case 0:                 return u->r->theme != THEME_LIGHT;   /* dark */
        case 3:                 return u->artPref == 1;              /* screenshot */
        case 4:                 return u->sndStartup;
        case 5:                 return u->sndShutdown;
        case 7:                 return u->catList;
        case SET_ROW_MENUBAR:   return u->hideMenuBar;
        case SET_ROW_TITLEBAR:  return u->hideTitleBar;
        case SET_ROW_CDINSERT:  return u->cdEnable;
        default:                return 0;
    }
}

void ui_setting_value(Ui *u, int row, char *out)
{
    char num[16];
    out[0] = '\0';
    switch (row) {
        case 1:
            if      (u->env->pixelSize >= 32) strcpy(out, "Millions");
            else if (u->env->pixelSize >= 16) strcpy(out, "Thousands");
            else { l2s(u->env->pixelSize, num); strcpy(out, num); strcat(out, "-bit"); }
            break;
        case 2:
            if (u->vol < 0) strcpy(out, "n/a");
            else { l2s(u->vol, num); strcpy(out, num); strcat(out, " / 7"); }
            break;
        case 6:
            strcpy(out, kViewName[(u->view >= 0 && u->view < VIEW_N) ? u->view : 0]);
            break;
        case 8:
            l2s(u->carousel, num); strcpy(out, num);
            break;
        case SET_ROW_TEXTSIZE:
            strcpy(out, u->r->textSize <= TEXT_SMALL ? "Small" :
                        u->r->textSize >= TEXT_LARGE ? "Large" : "Medium");
            break;
        case SET_ROW_GRIDSTYLE:
            strcpy(out, kGridStyle[(u->gridStyle >= 0 && u->gridStyle < GRID_N) ? u->gridStyle : 0]);
            break;
        case SET_ROW_CDTIMEOUT:
            l2s(u->cdTimeout, num); strcpy(out, num); strcat(out, " sec");
            break;
        case SET_ROW_APPEARANCE:
            if (u->r->appearancePref == APPEAR_AUTO) {   /* Auto: show what it resolves to */
                strcpy(out, "Auto (");
                strcat(out, appearance_name(u->r->appearance));
                strcat(out, ")");
            } else {
                strcpy(out, appearance_name(u->r->appearancePref));
            }
            break;
        default: break;
    }
}

int ui_setting_step(Ui *u, int row, int dir) { return settings_adjust_row(u, row, dir); }

UiCommand ui_key(Ui *u, char ch)
{
    UiCommand cmd = UI_NONE;

    /* Quit-confirm modal: Return = Quit (default), Esc = Cancel. */
    if (u->mode == UI_MODE_QUITCONFIRM) {
        if (ch == kCharReturn || ch == kCharEnter) return UI_QUIT;
        if (ch == kCharEscape) { u->mode = UI_MODE_LIST; ui_draw(u); }
        return UI_NONE;
    }

    /* First-run chooser is modal: Up/Down pick, Return/Esc confirm + persist. */
    if (u->mode == UI_MODE_SETUP) {
        UiCommand sc = UI_NONE;
        int       old = u->setupSel;
        switch (ch) {
            case kCharUp:    if (u->setupSel > 0) u->setupSel--; break;
            case kCharDown:  if (u->setupSel < VIEW_N - 1) u->setupSel++; break;
            case kCharReturn:
            case kCharEnter:
            case kCharEscape:
                u->view = u->setupSel;
                u->mode = UI_MODE_LIST;
                u->bgValid = 0;
                ui_draw(u);                 /* draw the chosen browse view */
                return UI_PREFS_DIRTY;       /* persist the view + mark first-run done */
        }
        if (u->setupSel != old) ui_draw(u);  /* only repaint when the selection moved */
        return sc;
    }

    /* Type-to-filter (find as you type) in EVERY browse view: a printable key — and
     * Backspace — narrows the current category. Plain keys are reserved for this, so
     * the launch hotkeys + Info/Box-Art/Theme shortcuts are Cmd-modified (ui_key_cmd,
     * dispatched by main). Arrows / Return / Esc are sub-0x20 and fall through to
     * navigation / launch / the Esc handler below. */
    if (u->mode == UI_MODE_LIST && !u->safe && !u->settingsFocus && u->m->loader) {
        if ((unsigned char)ch >= 0x20 && (unsigned char)ch < 0x7F) {
            int l = (int)strlen(u->filter);
            if (l < (int)sizeof u->filter - 1) {
                u->filter[l] = ch; u->filter[l + 1] = '\0';
                ui_filter_apply(u);
                ui_draw(u);
            }
            return UI_NONE;
        }
        if (ch == kCharBackspace && u->filter[0]) {
            u->filter[strlen(u->filter) - 1] = '\0';
            ui_filter_apply(u);
            ui_draw(u);
            return UI_NONE;
        }
    }

    /* Tab cycles the browse view (Carousel -> Icon -> List) — interim until the
     * View menu lands; persisted. */
    if (ch == '\t' && u->mode == UI_MODE_LIST && !u->settingsFocus && !u->safe) {
        ui_filter_clear(u);                 /* the filter is List-view only */
        u->view = (u->view + 1) % VIEW_N;
        u->bgValid = 0;
        ui_draw(u);
        return UI_PREFS_DIRTY;
    }

    /* Control Panels list: navigate, Return opens via the Finder, Esc back to the
     * browse screen (the Settings window it was opened from has already closed). */
    if (u->mode == UI_MODE_CTLPANELS) {
        switch (ch) {
            case kCharUp:    if (u->cdevSel > 0) u->cdevSel--; break;
            case kCharDown:  if (u->cdevSel < u->ncdevs - 1) u->cdevSel++; break;
            case kCharReturn:
            case kCharEnter:
                if (u->ncdevs > 0) { ui_draw(u); return UI_OPEN_CDEV; }
                break;
            case kCharEscape: u->mode = UI_MODE_LIST; break;
        }
        ui_draw(u);
        return UI_NONE;
    }

    /* Gear focused on the list screen (reached by Left at the first category):
     * Return opens the real Settings window (main.c), Esc opens the Esc menu. */
    if (u->mode == UI_MODE_LIST && u->settingsFocus) {
        switch (ch) {
            case kCharReturn:
            case kCharEnter:  u->settingsFocus = 0; return UI_OPEN_SETTINGS;
            case kCharEscape: u->settingsFocus = 0; return UI_OPEN_MENU;
            default:          u->settingsFocus = 0; break;   /* any other key unfocuses */
        }
        ui_draw(u);
        return UI_NONE;
    }

    /* About card: any key returns to the list. */
    if (u->mode == UI_MODE_ABOUT) {
        u->mode = UI_MODE_LIST;
        ui_draw(u);
        return UI_NONE;
    }

    /* Preview mode: any other key returns to the list. */
    if (u->mode == UI_MODE_PREVIEW) {
        art_dispose(u->previewPic);
        u->previewPic = 0;
        u->mode = UI_MODE_LIST;
        ui_draw(u);
        return UI_NONE;
    }

    /* More Info: Return launches the title; any other key returns to the list. */
    if (u->mode == UI_MODE_INFO) {
        art_dispose(u->previewPic);
        u->previewPic = 0;
        u->mode = UI_MODE_LIST;
        if ((ch == kCharReturn || ch == kCharEnter) && model_cur_item(u->m)) {
            u->status[0] = '\0';
            return UI_LAUNCH;   /* launching covers the screen — skip the browse repaint */
        }
        ui_draw(u);
        return UI_NONE;
    }

    /* list / safe mode — the current browse view owns arrow navigation; the shared
     * keys (Esc / Return) below apply to every view. (Plain printables were consumed
     * by the filter above; Info / Box Art / Theme / launch hotkeys are Cmd-modified,
     * handled by ui_key_cmd.) */
    if (!u->safe && cur_view(u)->nav(u, ch)) {
        /* Navigating onto the gear (Left/Up past the first category) needs a full draw
         * so its focus ring — in the header, which the incremental blit never touches —
         * appears; an ordinary move stays incremental. */
        if (u->settingsFocus) ui_draw(u);
        else                  browse_redraw(u);
        return cmd;                 /* cmd == UI_NONE here */
    }
    switch (ch) {
        case kCharEscape:
            if (u->filter[0]) {                           /* Esc clears an active filter first */
                ui_filter_clear(u);
            } else {
                return UI_OPEN_MENU;                       /* open the Quick-Launch window */
            }
            break;
        case kCharReturn:
        case kCharEnter:
            if (!u->safe && model_cur_item(u->m)) {
                u->status[0] = '\0';
                cmd = UI_LAUNCH;
            }
            break;
    }
    /* Launching hands off to the game and tears down the launcher window, so the
     * pre-launch repaint was a wasted full-screen blit the user saw flash by. */
    if (cmd != UI_LAUNCH) ui_draw(u);
    return cmd;
}

/* Cmd-modified keys (main dispatches these when MenuKey finds no menu match): the
 * shortcuts that used to be plain keys, moved here so plain typing is free for the
 * find-as-you-type filter. Cmd-T theme, Cmd-P box art, Cmd-I info, and Cmd+<letter>
 * a per-item launch hotkey (doubles as a gamepad button via MiSTer's key map). The
 * browse screen only; Cmd-I also arrives via File > Get Info (same action). */
UiCommand ui_key_cmd(Ui *u, char ch)
{
    int lo = ((unsigned char)ch >= 'A' && (unsigned char)ch <= 'Z') ? ch + 32 : (unsigned char)ch;
    if (u->safe || u->mode != UI_MODE_LIST || u->settingsFocus) return UI_NONE;
    if (lo == 't') {
        render_toggle_theme(u->r);
        u->bgValid = 0;
        ui_draw(u);
        return UI_PREFS_DIRTY;
    }
    if (lo == 'p') {
        const CatItem *it = model_cur_item(u->m);
        const char *base = it ? (it->image[0] ? it->image : it->shot) : 0;
        if (base && base[0]) { u->previewPic = load_item_art(u, base); u->mode = UI_MODE_PREVIEW; }
        ui_draw(u);
        return UI_NONE;
    }
    if (lo == 'i') {
        const CatItem *it = model_cur_item(u->m);
        if (it) {
            const char *base = art_base(u, it);
            if (base && base[0]) u->previewPic = load_item_art(u, base);
            u->mode = UI_MODE_INFO;
            ui_draw(u);
        }
        return UI_NONE;
    }
    if ((unsigned char)ch >= 0x20 && model_select_hotkey(u->m, ch)) {
        u->status[0] = '\0';
        ui_draw(u);
        return UI_LAUNCH;
    }
    return UI_NONE;
}

/* Mouse equivalent of ui_key: hit-test a window-local click (main does the
 * GlobalToLocal) and return the same UiCommand the keyboard path would, redrawing
 * first so the click gives immediate feedback. Mirrors ui_key's per-mode shape.
 * Browse screen: the gear opens the menu hub; the ◀▶ arrows and a side tile move
 * the selection; the centred "^ cat v" band changes category (left half = prev,
 * right = next); the Launch button launches. Modal panels hit-test their rows and
 * dismiss on a click outside the panel (the universal mouse "Back"). */
UiCommand ui_click(Ui *u, Point pt)
{
    /* Quit-confirm modal: the Quit / Cancel buttons are real controls (handled in
     * main before ui_click); a click outside the panel cancels. */
    if (u->mode == UI_MODE_QUITCONFIRM) {
        Rect panel, qb, cb;
        quitconfirm_rects(u, &panel, &qb, &cb);
        if (!PtInRect(pt, &panel)) { u->mode = UI_MODE_LIST; ui_draw(u); }
        return UI_NONE;
    }

    /* First-run chooser: a click on a row picks that view and continues. */
    if (u->mode == UI_MODE_SETUP) {
        int i;
        for (i = 0; i < VIEW_N; i++) {
            Rect rr; setup_row_rect(u, i, &rr);
            if (PtInRect(pt, &rr)) {
                u->setupSel = i; u->view = i;
                u->mode = UI_MODE_LIST; u->bgValid = 0;
                ui_draw(u);
                return UI_PREFS_DIRTY;
            }
        }
        return UI_NONE;
    }

    /* Safe (no-catalog) screen: a click opens the Quick-Launch menu so Restart /
     * Shut Down stay reachable with the mouse. */
    if (u->safe) return UI_OPEN_MENU;

    if (u->mode == UI_MODE_CTLPANELS) {
        int   W = win_w(u), H = win_h(u);
        int   pw = 320, rows = 9, ph = rows * (ROW_H + 2) + 56;
        short px = (short)((W - pw) / 2), py = (short)((H - ph) / 2);
        Rect  panel;
        int   i;
        SetRect(&panel, px, py, (short)(px + pw), (short)(py + ph));
        if (!PtInRect(pt, &panel)) { u->mode = UI_MODE_LIST; ui_draw(u); return UI_NONE; }
        for (i = 0; i < rows; i++) {
            int   idx = u->cdevTop + i;
            short y0  = (short)(py + 38 + i * (ROW_H + 2));
            Rect  rr;
            if (idx >= u->ncdevs) break;
            SetRect(&rr, (short)(px + 4), y0, (short)(px + pw - 4), (short)(y0 + ROW_H));
            if (PtInRect(pt, &rr)) {
                if (idx == u->cdevSel) { ui_draw(u); return UI_OPEN_CDEV; }  /* re-click opens */
                u->cdevSel = idx;
                break;
            }
        }
        ui_draw(u);
        return UI_NONE;
    }

    /* Full-screen info / preview / about cards: any click returns to the list. */
    if (u->mode == UI_MODE_INFO || u->mode == UI_MODE_PREVIEW || u->mode == UI_MODE_ABOUT) {
        if (u->previewPic) { art_dispose(u->previewPic); u->previewPic = 0; }
        u->mode = UI_MODE_LIST;
        ui_draw(u);
        return UI_NONE;
    }

    /* ---- browse screen (UI_MODE_LIST) ---- */
    {
        UiCommand cmd = UI_NONE;
        int       wasFocus = u->settingsFocus;
        u->settingsFocus = 0;                        /* a click takes focus off the gear */

        /* The Settings button is a real control (caught by FindControl in main.c before
         * this runs); the category little-arrows + the active view own the rest. */
        if ((u->view == VIEW_CAROUSEL || u->view == VIEW_ICON) && model_cur_cat(u->m)) {
            Rect step;
            cat_stepper_rect(u, &step);
            if (PtInRect(pt, &step)) {
                model_move_cat(u->m, pt.v < (short)((step.top + step.bottom) / 2) ? -1 : +1);
                browse_redraw(u);
                return UI_NONE;
            }
        }
        /* The active view owns selection / launch / category hit-testing. A click while
         * the gear was focused forces a full redraw so its focus ring (in the header,
         * which the incremental blit never touches) is cleared. */
        if (cur_view(u)->click && cur_view(u)->click(u, pt, &cmd)) {
            if (cmd != UI_LAUNCH) { if (wasFocus) ui_draw(u); else browse_redraw(u); }
            return cmd;
        }
        /* A click on empty space changed nothing — repaint only if it actually did
         * (the gear losing focus); otherwise leave the screen alone (no full reblit). */
        if (wasFocus) ui_draw(u);
        return UI_NONE;
    }
}

/* ---- menu-bar entry points (called by main.c's MenuSelect/MenuKey dispatch) ----
 * Thin wrappers so the System menu bar drives the same state the keyboard does;
 * each dismisses any open panel/card first, sets the new mode/state, and repaints. */
void ui_show_about(Ui *u)
{
    u->mode = UI_MODE_ABOUT;
    ui_draw(u);
}

void ui_confirm_quit(Ui *u)
{
    u->settingsFocus = 0;
    u->mode = UI_MODE_QUITCONFIRM;
    ui_draw(u);
}

void ui_show_info(Ui *u)
{
    const CatItem *it;
    if (u->safe) return;
    if (u->previewPic) { art_dispose(u->previewPic); u->previewPic = 0; }
    it = model_cur_item(u->m);
    if (it) {
        const char *base = art_base(u, it);
        if (base && base[0]) u->previewPic = load_item_art(u, base);
        u->mode = UI_MODE_INFO;
    } else {
        u->mode = UI_MODE_LIST;
    }
    ui_draw(u);
}

/* Scroll the List panes so the current category + item are visible — used when the
 * List view is (re)entered, since the selection may sit outside the default top-of-list
 * view. A no-op away from the List view (the offsets are only read there). */
void ui_list_reveal(Ui *u)
{
    list_reveal_item(u);
    list_reveal_cat(u);
}

void ui_set_view(Ui *u, int view)
{
    if (view < 0 || view >= VIEW_N) return;
    u->settingsFocus = 0;
    u->mode = UI_MODE_LIST;            /* dismiss any panel so the new view shows */
    if (u->view != view) { ui_filter_clear(u); u->view = view; u->bgValid = 0; }
    if (view == VIEW_LIST) ui_list_reveal(u);   /* keep the selection on-screen */
    ui_draw(u);
}
